const PROVISION_INDEX = [{"id": "s1-0", "num": "§1.0", "name": "Right of Access to Courts", "text": "Self-executing right: every person may seek legal remedy for any rights violation. Court access cannot be made meaninglessly expensive through procedural costs. If the Legislature fails to fund legal aid, courts appoint counsel at public expense until a statutory framework exists — the self-executin"}, {"id": "s1-1", "num": "§1.1", "name": "Individual Sovereignty Floor", "text": "Every person holds an "}, {"id": "s1-2", "num": "§1.2", "name": "Prohibition of Torture and Cruel Treatment", "text": "Absolute prohibition on torture, cruel treatment, and degrading punishment. "}, {"id": "s1-3", "num": "§1.3", "name": "Prohibition of Slavery and Forced Labor", "text": "Slavery, forced labor, debt bondage, and compelled service are prohibited absolutely and in all forms. This provision is permanently unamendable (§15.3.a) — no future majority can restore any form of servitude through constitutional amendment, even a unanimous one. The unamendable status reflects th"}, {"id": "s1-4", "num": "§1.4", "name": "Freedom of Expression", "text": "No branch, agency, official, or instrumentality of the Republic or any State may abridge the freedom of speech, press, or assembly in any medium — physical or digital. §1.4.a prohibits censorship by proxy (government coercion of private entities to suppress speech); §1.4.b establishes separation of "}, {"id": "s1-4-a", "num": "§1.4.a", "name": "Censorship by Proxy", "text": "The most operationally significant speech protection. Governments that cannot censor directly regularly achieve the same result by threatening, incentivizing, or coercing private platforms and institutions to suppress speech on their behalf. This provision closes that route: a government agent who p"}, {"id": "s1-4-b", "num": "§1.4.b", "name": "Separation of Church and State", "text": "No religion may be established by law, and public funds directed to religious organizations must comply with the equality requirements of §1.8. The separation of church and state is structural, not merely preferential."}, {"id": "s1-5", "num": "§1.5", "name": "Freedom of Thought, Conscience, and Religion", "text": "Every person has the right to hold, practice, change, or decline any belief and to manifest it through worship, observance, practice, and teaching. No person may be compelled to participate in any religious observance contrary to their beliefs. Free exercise does not authorize harm to others and cre"}, {"id": "s1-6", "num": "§1.6", "name": "Freedom of Association", "text": "Every person has the right to freely associate with others for any lawful purpose — including political parties, trade unions, civic organizations, and professional associations. The State may not compel membership as a condition of employment or civic participation, nor prohibit any association sol"}, {"id": "s1-7", "num": "§1.7", "name": "Right to Petition", "text": "Every citizen has the right to petition any branch of government on any matter of public or personal concern. All petitions must receive a formal response within a Legislature-defined period. The subject and status of petitions are published to the National Record System; petitioner identity is with"}, {"id": "s1-8", "num": "§1.8", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. No person may be discriminated against on the basis of the enumerated characteristics. Distinctions based on race, ethnicity, religion, sex, sexual orientation, gender identity, national origin, or disability are presumptively unconstitutional, requiring a compe"}, {"id": "s1-9", "num": "§1.9", "name": "Bodily Autonomy and Digital Privacy", "text": "Three protections: §1.9.a — absolute right to refuse any medical procedure or biological sampling; no mandate is permissible under any emergency without uncoerced revocable written consent. §1.9.b — individuals own their personal data, likeness, and biometric information; government data collection "}, {"id": "s1-9-a", "num": "§1.9.a", "name": "Physical Sovereignty", "text": "Every person has the absolute right to refuse any medical procedure or biological sampling. No mandate is permissible under any declared emergency unless the individual provides uncoerced, revocable written consent."}, {"id": "s1-9-b", "num": "§1.9.b", "name": "Data Ownership", "text": "Individuals own their personal data, likeness, and biometric information. Data collected by any government actor is subject to strict necessity limits — it may not be retained beyond the purpose for which it was collected, shared with third parties without..."}, {"id": "s1-9-c", "num": "§1.9.c", "name": "Encryption Protection", "text": "Cryptographic keys are private property. No court or agency may compel their disclosure. Absolute rule, consistent with §1.16's self-incrimination prohibition — "}, {"id": "s1-10", "num": "§1.10", "name": "Inviolability of the Home and Property Rights", "text": "§1.10.a extends \"home\" to all physical residences and digital spaces secured by private cryptographic keys; State access requires a precise warrant recorded on the NRS before execution; general warrants are absolutely prohibited. §1.10.b governs eminent domain: requires proof of absolute public nece"}, {"id": "s1-10-a", "num": "§1.10.a", "name": "Home and Digital Privacy", "text": "'Home' extends to all physical residences and all digital spaces secured by private cryptographic keys. Access requires a warrant specifying the precise data target or physical space, "}, {"id": "s1-10-b", "num": "§1.10.b", "name": "Eminent Domain", "text": "Seizure of private property requires proof of absolute public necessity, payment of 150% of fair market value, and NRS publication. Private-to-private transfer via eminent domain — using government condemnation to benefit another private party — is constitutionally prohibited."}, {"id": "s1-11", "num": "§1.11", "name": "Self-Defense and the Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting must not be infringed. States may establish proportionate licensing requirements (§1.11.b) but may not impose requirements that function as effective prohibitions on lawful ownership (§1.11.c). The burden of proof lies with the State t"}, {"id": "s1-11-a", "num": "§1.11.a", "name": "Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting "}, {"id": "s1-11-b", "num": "§1.11.b", "name": "State Licensing Latitude", "text": "States may establish licensing and safety training requirements as a condition of carrying or possessing firearms. States may regulate the exercise of the right but may not use regulation as a prohibition by another name."}, {"id": "s1-11-c", "num": "§1.11.c", "name": "Non-Prohibition Principle", "text": "No State requirement may function as an effective prohibition on keeping or bearing arms. A requirement is an effective prohibition if it imposes costs, delays, or conditions that make lawful ownership practically inaccessible to ordinary citizens. The burden of proof lies with the State to demonstr"}, {"id": "s1-12", "num": "§1.12", "name": "Freedom of Movement and Labor", "text": "All Inhabitants have the right to travel and reside anywhere within the Republic. State professional licensing requirements may not create barriers to labor mobility; licenses issued under State law are recognized throughout the Republic. Every person has the right to form and join trade unions and "}, {"id": "s1-13-a", "num": "§1.13.a", "name": "First Appearance", "text": "Any person taken into custody must appear before a judicial officer within "}, {"id": "s1-13-b", "num": "§1.13.b", "name": "Habeas Corpus Response Deadline", "text": "A court receiving a habeas corpus petition must rule within 48 hours of filing. No procedural rule may extend this deadline. A court that fails to rule within 48 hours is deemed to have found the detention unlawful — the detained person must be released or brought before a judicial officer immediately a judicial officer immediately."}, {"id": "s1-13-c", "num": "§1.13.c", "name": "Habeas Corpus", "text": "Any person detained by the State has the absolute right to challenge the lawfulness of their confinement before a judge at any time. "}, {"id": "s1-14-a", "num": "§1.14.a", "name": "Right to Counsel", "text": "Any person accused of a crime or subject to detention has the right to retain and consult with a lawyer before questioning. If they cannot afford counsel, the Republic provides it. The right attaches "}, {"id": "s1-14-b", "num": "§1.14.b", "name": "Caseload Guarantee", "text": "the Legislature must establish maximum caseload limits for publicly funded defense — ensuring that the right to counsel means genuine preparation, not nominal presence. Public defenders must be resourced equivalently to prosecutorial offices handling comparable cases."}, {"id": "s1-14-c", "num": "§1.14.c", "name": "Right to Be Informed of Charges", "text": "Any person detained or accused must be informed promptly, in plain language they understand, of the specific grounds for their detention and the charges being considered. Detention without meaningful explanation of its basis is unconstitutional from its first moment."}, {"id": "s1-14-d", "num": "§1.14.d", "name": "Right to Full Disclosure", "text": "Any accused person has the right to full disclosure of all State evidence — "}, {"id": "s1-15-a", "num": "§1.15.a", "name": "Speedy Trial Principle", "text": "Every accused person has the right to trial without unreasonable delay. Delay caused by the State is not a neutral fact — prolonged pre-trial detention is itself a punishment imposed without verdict. What constitutes unreasonable delay is defined by the Legislature in statute, subject to judicial re"}, {"id": "s1-15-b", "num": "§1.15.b", "name": "Bail Proportionality", "text": "Pre-trial detention may only be ordered where the court makes a specific, individualized finding that the accused poses a genuine flight risk or documented danger to an identifiable person. Financial inability to post bail does not justify detention — "}, {"id": "s1-15-c", "num": "§1.15.c", "name": "Protection from Trial Penalties", "text": "The right to trial may not be penalized. A defendant who exercises their right to trial may not receive a harsher sentence than they would have received by entering a guilty plea for the same offense. "}, {"id": "s1-15-d", "num": "§1.15.d", "name": "Source Code Right", "text": "Any accused person has the right to inspect, challenge, and rebut any algorithm, automated system, statistical model, or raw dataset used as evidence or to generate a score influencing their case. Technology-opaque evidence against which no defense can be mounted is constitutionally inadmissible."}, {"id": "s1-16", "num": "§1.16", "name": "Right to Silence", "text": "No person may be compelled to testify against themselves or to produce self-incriminating evidence. The right of silence is complete — silence may not be commented upon or used to draw adverse inferences. Consistent with §1.9.c, this extends to cryptographic keys."}, {"id": "s1-17", "num": "§1.17", "name": "Right to a Public Trial", "text": "Every accused person has the right to a public trial before a judge and, in criminal matters, a jury of peers. Secret or closed proceedings are constitutionally prohibited except for the minimal portion where a specific witness's safety requires it — and "}, {"id": "s1-18-a", "num": "§1.18.a", "name": "No Retroactive Criminal Laws", "text": "No person may be convicted of an act that was not defined as a criminal offense at the time it was committed. No sentence may exceed the maximum available at the time of the offense. The prohibition on retroactive criminal law is absolute and "}, {"id": "s1-18-b", "num": "§1.18.b", "name": "Double Jeopardy", "text": ""}, {"id": "s1-19", "num": "§1.19", "name": "Right to Democratic Participation", "text": "No government action may make voting materially more difficult for any eligible citizen. This covers not only formal disenfranchisement but practical barriers: polling place closures, identification requirements that function as wealth or document-access tests, registration obstacles designed to sup"}, {"id": "s1-20", "num": "§1.20", "name": "Right to Marry and Found a Family", "text": "The right to marry or form a legally recognized partnership belongs to any two consenting adults regardless of sex, gender, or sexual orientation. The Republic must recognize such partnerships "}, {"id": "s1-21", "num": "§1.21", "name": "Rights of Children", "text": "Every child has the right to protection from exploitation, abuse, and neglect. In all State actions affecting minors, the welfare and best interests of the child are the primary consideration — not merely one factor to be weighed. The protection of children is the one area where the Individual Sover"}, {"id": "s1-22", "num": "§1.22", "name": "Environmental Accountability", "text": "Article I's environmental provisions establish two constitutional obligations: Government Non-Harm (§1.22.a) prevents authorities from knowingly exposing communities to environmental hazards without disclosure, consultation, and mitigation; Environmental Stewardship (§1.22.b) creates an enforceable "}, {"id": "s1-22-a", "num": "§1.22.a", "name": "Government Non-Harm", "text": "No government authority may knowingly expose any community of Inhabitants to environmental hazards without full disclosure, meaningful consultation, and proportionate mitigation. The Government Non-Harm principle makes environmental poisoning of communities a "}, {"id": "s1-22-b", "num": "§1.22.b", "name": "Environmental Stewardship", "text": "The long-term stewardship of the Republic's natural environment is a constitutional obligation of the federal government — not aspirational language. It creates an "}, {"id": "s1-23", "num": "§1.23", "name": "Federal Education Assistance", "text": "Three interlocking education provisions: §1.23.a requires the Republic to fund education assistance so no child's opportunity depends on their territory's wealth. §1.23.b requires public education to equip students to meet the Constitutional Logic Test standard — education for citizenship is a const"}, {"id": "s1-23-a", "num": "§1.23.a", "name": "Federal Education Assistance", "text": "The Republic must provide adequate education assistance to States and Territories so that no child's educational opportunity is determined primarily by the wealth of their territory. Federal assistance must address the gap between what a jurisdiction can fund locally and what the constitutional lite"}, {"id": "s1-23-b", "num": "§1.23.b", "name": "Constitutional Literacy", "text": "The Republic's constitutional literacy standard for citizenship purposes is the CLT, defined in §5.4. Public education must equip students to meet that standard — education for citizenship is a constitutional obligation, not a civic nicety."}, {"id": "s1-23-c", "num": "§1.23.c", "name": "Parental Right", "text": "Parents retain the right to educate children through alternative means — homeschooling, faith-based schools, alternative institutions — provided those alternatives meet the constitutional literacy standard. The Republic may set the floor; it may not mandate the method."}, {"id": "s1-24", "num": "§1.24", "name": "Housing Non-Exclusion", "text": "Article I's housing provisions create constitutional barriers to exclusion and a constitutional obligation to provide. The Non-Exclusion Principle (§1.24.a) prohibits exclusionary zoning and any regulatory mechanism designed to keep certain populations out. The BNF Housing Obligation (§1.24.b) ancho"}, {"id": "s1-24-a", "num": "§1.24.a", "name": "Non-Exclusion Principle", "text": "No government authority — federal, State, or local — may use regulatory or land-use powers to exclude any person from access to housing on the basis of any characteristic enumerated in §1.8. Exclusionary zoning designed to keep certain populations out of a community is constitutionally prohibited."}, {"id": "s1-24-b", "num": "§1.24.b", "name": "BNF Housing Obligation", "text": "The Republic's obligation to ensure housing access for persons who cannot independently secure it is part of the Basic Needs Floor under §10.1. This provision anchors housing as a BNF category and makes housing exclusion an enforceable constitutional violation."}, {"id": "s1-25-a", "num": "§1.25.a", "name": "Emergency Derogation — Declaration Requirements", "text": "Emergency derogation of Article I rights requires a precisely structured declaration specifying: the nature of the emergency, which rights are limited, the geographic scope, the duration, and the review mechanism. The specificity requirement prevents open-ended emergency licenses — the government mu"}, {"id": "s1-25-b", "num": "§1.25.b", "name": "Non-Derogable Rights", "text": ""}, {"id": "s1-25-c", "num": "§1.25.c", "name": "Inspectorate Continuity", "text": "The three Inspectorates continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration. Accountability infrastructure is precisely most important when emergency powers are active."}, {"id": "s1-25-d", "num": "§1.25.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. Judicial review of any emergency measure is available to any citizen at any time, and courts may rule during the emergency that a specific measure is unconstitutional."}, {"id": "s1-25-e", "num": "§1.25.e", "name": "No Permanent Emergency", "text": ""}, {"id": "s1-26", "num": "§1.26", "name": "Associated Community Residents", "text": "Every person residing within any Associated Community operating under a compact with the Republic holds the full protections of Article I, enforceable directly by federal courts regardless of the Associated Community's internal governance structure. No compact provision may limit or qualify any Arti"}, {"id": "s1-27", "num": "§1.27", "name": "Non-Refoulement", "text": "The absolute prohibition on returning any person to persecution — one of the six permanently unamendable provisions under §15.3.a. No exception for immigration status, mode of entry, or emergency declaration. The Republic cannot return, expel, or extradite any person to a territory where they face genuine risk of persecution, torture, or deprivation of life based on race, religion, nationality, political opinion, or group membership. This provision is the constitutional foundation of the asylum "}, {"id": "s1-28", "num": "§1.28", "name": "Medical Autonomy", "text": "Medical decisions belong to the patient and their licensed provider — not to the State. The first paragraph establishes this as a constitutional principle: government cannot require or forbid specific treatments in the individual patient-provider relationship. The State's legitimate role is safety a"}, {"id": "s1-29", "num": "§1.29", "name": "Right to Privacy", "text": "The general right to privacy is the interpretive umbrella over all specific privacy protections in the constitution. A person has the right to privacy in their person, home, communications, associations, health, and personal data — the enumeration signals breadth, not limitation. The general right g"}, {"id": "s1-29-a", "num": "§1.29.a", "name": "Searches and Seizures", "text": "No unreasonable search or seizure of person, home, property, communications, or data. Any authorized search must be narrowly scoped, judicially approved before execution, and recorded on the NRS. General warrants — broad or unspecified authorizations — are absolutely prohibited. Digital spaces secur"}, {"id": "s1-29-b", "num": "§1.29.b", "name": "Medical Privacy", "text": "Medical information, health records, genetic data, and bodily condition are private. Government compulsion requires a specific judicial order in active legal proceedings, limited to what those proceedings directly require. Public health law disclosures must be proportionate, time-limited, and NRS-re"}, {"id": "s1-29-c", "num": "§1.29.c", "name": "Communications and Data", "text": "Government collection of private communications or personal data requires specific judicial authorization identifying the person, the data sought, and the collection period. Bulk collection — without individual identification — is prohibited outright. Private-sector entities cannot be compelled to c"}, {"id": "s1-29-d", "num": "§1.29.d", "name": "Intelligence Firewall", "text": "Migrated from §12.3 with language unchanged. All domestic intelligence operations against Republic citizens are permanently prohibited and constitutionally void. Any such order is reported to the NRS by the EI. This prohibition is non-derogable — no emergency, treaty, or statute can suspend it. Plac"}, {"id": "s1-29-e", "num": "§1.29.e", "name": "Associational Privacy", "text": "The explicit provision that closes the gap between freedom of association (§1.6) and privacy in associations. §1.6 protects the right to associate; §1.29.e protects the right to keep private who you associate with and the fact that you do. A government can comply with §1.6 while violating §1.29.e — "}, {"id": "s2-1", "num": "§2.1", "name": "The President — Term and Transfer", "text": "The opening provision of the Presidential domain. Authority is defined and bounded — military command, foreign affairs, intelligence, treaty negotiation, trade agreements, domain officer appointments, and the domain-scoped veto. The structure is intentional: Presidential authority is enumerated; PM "}, {"id": "s2-1-ac", "num": "§2.1.a–c", "name": "Military Authority — Three Tiers", "text": "Introductory note for the three-tier military authorization framework. Presidential military authority flows through three tiers of escalating democratic consent. Each tier requires more authorization and covers a longer period. The design inverts the historical pattern of executive war powers — the"}, {"id": "s2-1-a", "num": "§2.1.a", "name": "Tier 1 — Immediate Defensive Response", "text": "Tier 1: immediate defensive response — self-executing, no prior authorization required. The only presidential power that can be exercised without legislative consent. Strictly bounded: defensive operations only, expires when the immediate threat is neutralized, 12-hour notification to both chambers "}, {"id": "s2-1-b", "num": "§2.1.b", "name": "Tier 2 — Senate Armed Services Authorization", "text": "Tier 2: Senate Armed Services Committee authorization — required within 96 hours for any offensive operation or sustained defensive deployment. Simple majority of the Committee following a classified presidential briefing. Covers 30 days. If the full Legislature does not pass a Tier 3 Declaration wi"}, {"id": "s2-1-c", "num": "§2.1.c", "name": "Tier 3 — Legislative Declaration of Defense", "text": "Tier 3: Legislative Declaration of Defense — the full democratic authorization. 2/3 concurrent majority of both chambers. Must state the §12.1 authorized purpose. Renewable every 180 days — failure to renew terminates all operations and expenditure with no presidential override. Maximum 5 years then"}, {"id": "s2-1-d", "num": "§2.1.d", "name": "Funding Lock", "text": "The funding lock: the President has no authority to spend domestic funds. All military expenditure requires PM certification. Tier 1 defensive operations carry an automatic 96-hour Emergency Defense Allocation — self-executing, not subject to PM Fiscal Objection. Beyond 96 hours, PM must certify or "}, {"id": "s2-1-e", "num": "§2.1.e", "name": "Privacy Firewall", "text": "Cross-references §1.29.d as the authoritative Intelligence Firewall provision. The prohibition on domestic intelligence operations against Republic citizens is non-derogable and permanent — governed by §1.29.d. §2.1.e previously restated the prohibition in language not identical to §1.29.d. Now redi"}, {"id": "s2-1-f", "num": "§2.1.f", "name": "Presidential Veto — Scope", "text": "Domain-scoped veto — deliberately the most limited presidential veto in any constitutional design. The President may veto only bills raising a genuine constitutional concern within the security domain: military operations, intelligence, treaty obligations, border security. A general or speculative s"}, {"id": "s2-1-f-i", "num": "§2.1.f.i", "name": "Judicial Review and Override", "text": "Automatic expedited SC review within 48 hours of petition by either Speaker. The Court determines only whether the bill genuinely raises a constitutional concern within the President's defined domain — not whether the President's security judgment is correct. If the bill does not raise a genuine dom"}, {"id": "s2-1-g", "num": "§2.1.g", "name": "Presidential Clemency", "text": "Presidential clemency is domain-scoped: military law and national security offenses only. Before any grant, the EI publishes a factual background report — the petitioner's record, conviction circumstances, and prior EI findings — simultaneously to the NRS. Self-clemency is constitutionally prohibite"}, {"id": "s2-1-h", "num": "§2.1.h", "name": "Dual Executive Conflict Resolution During Active Operations", "text": "Conflict resolution during active military operations — four steps: written NRS objection within 6 hours; 12-hour negotiation window; SC emergency domain determination within 24 hours on petition; pending ruling, Presidential order governs only for operations directly connected to the active military situation while all other government functions follow the PM. Prevents either executive from using military operations as cover to assert authority over the other's domain. Where an SC emergency dom"}, {"id": "s2-1-i", "num": "§2.1.i", "name": "International Trade Authority", "text": "President negotiates and concludes trade agreements; PM written concurrence required where materially affecting the domestic economy. The SC ruled in The Concurrence Dispute (Year 28) that national treatment obligations within Republic territory require PM concurrence — they directly govern how dome"}, {"id": "s2-1-j", "num": "§2.1.j", "name": "Presidential Officer Appointments and Removal", "text": "The three Presidential domain officers: Director of Intelligence, Secretary for Foreign Affairs, Secretary for Defense. PM nominates from the JI-maintained candidate registry; Senate confirms by simple majority. PM failure to nominate within 90 days triggers the Senate nomination pathway. Senate con"}, {"id": "s2-2", "num": "§2.2", "name": "The Prime Minister — Domestic Executive Domain", "text": "The PM domain opening — residual authority. Everything not enumerated as Presidential is the PM's. Domestic policy, fiscal policy, BNF administration, legislation review, judicial nominations, independent agency appointments, PM clemency. The PM answers to the House through the confidence mechanism "}, {"id": "s2-2-a", "num": "§2.2.a", "name": "The Record System Mandate", "text": "Domestic Policy Authority — the PM's broadest power. Healthcare, education, infrastructure, housing, labour, environment, all domestic regulatory frameworks. The residual nature of PM authority means any new policy domain that emerges belongs to the PM unless it clearly falls within the President's "}, {"id": "s2-2-b", "num": "§2.2.b", "name": "Duty of Refusal", "text": "PM appoints senior domestic officers from JI-maintained candidate registries. The registry requirement prevents purely political appointments. Senate confirmation provides a further check. PM removal of appointed officers requires published NRS reasons — arbitrary or politically motivated removal is"}, {"id": "s2-2-c", "num": "§2.2.c", "name": "PM Maximum Consecutive Service", "text": "Fiscal policy and budget — the PM's central domestic power. The annual budget originates with the PM and requires House passage. The PM's certification function for military expenditure is the financial check on the President's domain: no military operation runs without PM-certified funds."}, {"id": "s2-2-d", "num": "§2.2.d", "name": "Civil Service Integrity", "text": "Legislative Review Period — the PM reviews all enacted legislation. Three options: sign (or remain silent, triggering Deemed Enactment), Fiscal Objection, or Suspensive Veto. The PM's silence enacts a bill — there is no veto by inaction. The Suspensive Veto returns the bill to the Legislature, which"}, {"id": "s2-2-e", "num": "§2.2.e", "name": "Domestic Emergency Authority", "text": "Domestic Emergency Authority — the PM may declare a domestic emergency in response to natural disaster, public health crisis, or civil infrastructure failure. Strictly bounded: no suspension of Article I rights, 30-day initial period renewable by House approval, all emergency orders published to the"}, {"id": "s2-2-f", "num": "§2.2.f", "name": "PM Clemency", "text": "PM clemency for domestic offenses — same procedural structure as Presidential clemency: EI factual report published to NRS before any grant. Self-clemency prohibited under §2.9.b. The PM may not pardon Presidential domain offenses under §2.9.c. Broad amnesty for groups requires legislative action un"}, {"id": "s2-2-g", "num": "§2.2.g", "name": "Ministerial Appointments", "text": "PM Information Rights — the PM has a constitutional right to full and timely briefing on all national security matters affecting domestic interests. The President may not withhold information from the PM on grounds of security classification where the PM's domestic responsibilities are genuinely eng"}, {"id": "s2-2-h", "num": "§2.2.h", "name": "Administrative Acting Officer Framework", "text": "Acting PM provisions — who governs when the PM cannot. The most senior Domestic Affairs Council Officer (SDACO) serves as Caretaker PM. The SDACO's authority is limited to maintaining existing policy and emergency functions. Caretaker status expires when a new PM takes confidence."}, {"id": "s2-3-a", "num": "§2.3.a", "name": "Selection", "text": "The Constructive Vote of No Confidence — the House cannot simply vote 'no confidence' and leave a vacuum; it must simultaneously elect a replacement by absolute majority of full seated House membership. Both the removal and successor election occur in the same vote. This prevents parliamentary paral"}, {"id": "s2-3-b", "num": "§2.3.b", "name": "Constructive Vote of No Confidence", "text": "The 8-year maximum — no PM may serve more than 8 consecutive years. After 8 years, the PM must stand down even if the House would re-elect them. The 8-year maximum and the constructive vote operate independently — a PM reaching 8 years is replaced through a House election of a successor."}, {"id": "s2-3-c", "num": "§2.3.c", "name": "Caretaker Protocol", "text": "Initial election of the PM — the House elects the PM by absolute majority of full seated membership within 30 days of any general election. The House may attempt to elect a PM at any time. If the House has not elected a PM within 30 days, the SDACO continues as Caretaker PM. Where the House has not elected a PM within 30 days, the Senate may, by 2/3 supermajority of full seated membership, designate a serving House member as PM. A PM designated under this provision holds full constitutional PM a"}, {"id": "s2-4-ab", "num": "§2.4.a–b", "name": "Suspensive Veto and Fiscal Objection", "text": "Section opening for PM Objection Powers — two distinct tools: the Suspensive Veto for constitutional concerns, and the Fiscal Objection for solvency concerns. They operate on different grounds with different override mechanisms. The PM cannot veto purely on policy grounds — the objection must be con"}, {"id": "s2-4-a", "num": "§2.4.a", "name": "Suspensive Veto", "text": "Suspensive Veto — returns the bill to the Legislature with written constitutional grounds. Legislature may override by 2/3 of both chambers simultaneously. The PM must give the LI's constitutional analysis due consideration before issuing a Suspensive Veto. A veto issued purely for political reasons"}, {"id": "s2-4-b", "num": "§2.4.b", "name": "Fiscal Objection", "text": "Fiscal Objection — a narrower tool than the Suspensive Veto. The PM may object to legislation on specific solvency grounds: the bill, if enacted, would cause or materially worsen a structural deficit beyond constitutional thresholds. Requires MA assessment within 21 days. House may override by simpl"}, {"id": "s2-4-c", "num": "§2.4.c", "name": "Objection Limits", "text": "Deemed Enactment — if the PM neither signs, objects, nor vetoes within the Legislative Review Period, the bill is automatically enacted. Silence is not a veto. This prevents the PM from blocking legislation through inaction and forces the PM to take a public constitutional position on every bill."}, {"id": "s2-5-a", "num": "§2.5.a", "name": "Emergency Legislative Continuity", "text": "The Legislative Review Period — duration defined by statute, bounded between 7 and 30 days. The PM must act within the period. The period begins from final passage in both chambers, not from the PM's receipt of the bill."}, {"id": "s2-6", "num": "§2.6", "name": "Presidential Succession", "text": "Presidential Succession — a complete framework for filling a Presidential vacancy. The Speaker of the Senate serves as Acting President, immediately triggering a special presidential election. The design keeps succession within the elected political class rather than delegating it to an appointed of"}, {"id": "s2-6-a", "num": "§2.6.a", "name": "Presidential Succession Line", "text": "Acting Presidential Authority triggers automatically on Presidential death, resignation, removal, or certified permanent incapacity. The Senate Speaker assumes Acting Authority immediately — no gap, no confirmation required. The Senate Speaker's own Senate seat is simultaneously vacated; the Deputy "}, {"id": "s2-6-b", "num": "§2.6.b", "name": "Incapacity Certification", "text": "The 90-day permanence assessment — if Acting Presidential Authority extends beyond 90 consecutive days, the PM and the Senate Speaker must jointly assess whether the incapacity has become permanent. Assessment repeats every 30 days if temporary incapacity is certified. Failure to conduct the mandatory 90-day assessment is a constitutional failure for both the PM and the most senior SC justice."}, {"id": "s2-6-c", "num": "§2.6.c", "name": "Succession-Based Presidential Term", "text": "A person who assumes the presidency by succession does not thereby expend their single non-renewable term. They must stand for election at the next regular National Election Day presidential cycle, or at a special election within 90 days of succession, to continue beyond the succession period. If el"}, {"id": "s2-7", "num": "§2.7", "name": "Executive Transparency and NRS Obligations", "text": "New in v159. Fills the gap between §2.6 (Succession) and §2.8 (Emergency Governance) by consolidating the executive publication obligation that was previously only implied by §9.1. Both executives must publish all official acts — orders, certifications, vetoes, objections, determinations — to the NR"}, {"id": "s2-9-a", "num": "§2.9.a", "name": "Legislative Amnesty", "text": "Legislative Amnesty — only the Legislature may grant group amnesty, by simple majority of both chambers. No executive may grant group amnesty. Cannot extend to constitutional violations, official misconduct offenses, or crimes against the fundamental rights of §1.2 and §1.3. Subject to judicial revi"}, {"id": "s2-9-b", "num": "§2.9.b", "name": "Self-Clemency Absolute Prohibition", "text": "Self-clemency is absolutely prohibited. No elected or appointed official may grant clemency to themselves or to any person whose conviction, if enforced, would directly benefit the official financially, politically, or personally. An attempted self-clemency act is constitutionally void and itself a "}, {"id": "s2-9-c", "num": "§2.9.c", "name": "Cross-Chamber Clemency Review", "text": "Cross-chamber clemency prohibition — the President may not grant clemency for offenses committed in the PM's domestic domain, nor may the PM grant clemency for Presidential domain offenses. Prevents either executive from using clemency to protect the other's allies from accountability. Domains of cl"}, {"id": "s2-10", "num": "§2.10", "name": "Presidential Removal — Two Political Tracks", "text": "Presidential removal — two independent paths. Legislative: 2/3 of both chambers simultaneously following Inspectorate-certified findings. Popular: 15% citizen petition triggers a national referendum requiring 60% affirmative with 55% participation. The popular path exists precisely because the Legis"}, {"id": "s2-10-a", "num": "§2.10.a", "name": "Legislative Removal", "text": "Legislative removal grounds: verified constitutional breach, demonstrated permanent incapacity, or conviction for a disqualifying criminal offense. The LI and EI must jointly certify the grounds before a removal vote can proceed — prevents politically motivated removal."}, {"id": "s2-10-b", "num": "§2.10.b", "name": "Senate Referral to Popular Recall", "text": "Popular removal referendum — if the 15% petition threshold is met, the EC administers a referendum within 90 days. 60% affirmative with 55% participation required. A failed referendum cannot be re-initiated for 2 years on the same grounds."}, {"id": "s2-10-c", "num": "§2.10.c", "name": "One Referral Per Term", "text": "No second Senate referral to popular recall within the same presidential term. One-shot rule prevents a hostile Senate from using repeated recall elections as attrition. After a failed recall, the President serves out their term with the NRS record intact."}, {"id": "s3-1-a", "num": "§3.1.a", "name": "House Membership Floor", "text": "The House is the proportional chamber — seats allocated by population, minimum one per State, floor of one per 750,000 citizens, self-scaling with population. The opening sentence previously read \"the Legislature is the Republic's legislature\" — circular and uninformative. Now reads \"The Republic's "}, {"id": "s3-1-b", "num": "§3.1.b", "name": "Census Authority", "text": "The population census is conducted by the Legislative Inspectorate. The provision previously contained a lengthy inline explanation of why the LI (not the EI) conducts the census — accurate but belonging in commentary. Operative rule only: LI conducts the census."}, {"id": "s3-1-c", "num": "§3.1.c", "name": "Single-Subject Rule", "text": "Single-Subject Rule — every bill must address a single, clearly defined subject. Self-executing: a court finding that a bill addresses multiple unrelated subjects voids the entire act. The LI publishes a germaneness analysis for any amended bill returned to the House. No riders, no logrolling throug"}, {"id": "s3-1-d", "num": "§3.1.d", "name": "Bill Exposure", "text": "Bill Exposure Period — the full text of every bill must be published to the NRS for the minimum exposure period (Legislature defines by statute, not less than 7 days) before any final passage vote. A substantially amended bill resets the exposure clock."}, {"id": "s3-1-e", "num": "§3.1.e", "name": "Caretaker Activation and PM Formation", "text": "Legislative Calendar and Session — the Legislature must sit for a minimum number of days per year defined by statute. Emergency sessions may be called by the PM or by petition of 1/3 of either chamber. Prevents pocket-session governance — the Legislature cannot be prorogued into ineffectiveness."}, {"id": "s3-1-f", "num": "§3.1.f", "name": "House Term Limits", "text": "Compensation and Disclosure — legislative compensation is set by the LI on a formula tied to median citizen income, not by the Legislature itself. All financial interests of members must be disclosed to the EI and published to the NRS. The compensation formula prevents legislators from voting themse"}, {"id": "s3-2", "num": "§3.2", "name": "The Senate — States as Constitutional Actors", "text": "The Senate — 2 senators per State, 6-year staggered terms. Primary role: checking chamber. Must act on every House-passed bill (§3.2.c). Cannot originate fiscal legislation (§3.2.b). Amendment authority bounded by germaneness (§3.2.i). Confirmations, ratifications, and treaty approvals represent its"}, {"id": "s3-2-a", "num": "§3.2.a", "name": "Senator Terms and Limits", "text": "Senate composition — two senators per State regardless of population, elected by citizens of that State for 6-year non-renewable staggered terms. Staggering ensures no single election cycle can sweep the entire Senate. The 6-year term creates institutional continuity — senators serve 50% longer than"}, {"id": "s3-2-b", "num": "§3.2.b", "name": "Senate Speaker Role Limit", "text": "Fiscal origination — all revenue measures, appropriations, and debt ceiling changes must originate in the House. The Senate may amend fiscal legislation but cannot initiate it. Keeps fiscal accountability with the proportionally elected chamber."}, {"id": "s3-2-c", "num": "§3.2.c", "name": "Senate Must Act on Every House Bill", "text": "Senate Must Act — the Senate cannot table or indefinitely delay House-passed legislation. Must vote within the Legislature-defined period. If it does not act, Deemed Approval triggers automatically. The Senate may, by simple majority vote before the original review period expires, extend its review period once by a duration defined by statute where a bill's complexity warrants expert testimony or additional committee review; the extension vote and its duration are published to the NRS. The Senat"}, {"id": "s3-2-d", "num": "§3.2.d", "name": "Judicial Confirmation", "text": "Judicial Confirmation — the Senate confirms all judicial appointments by a supermajority defined by statute (not less than 55%, not more than 67% of full Senate membership). Failure to vote within the confirmation period triggers Deemed Confirmation. The supermajority requirement ensures judicial ap"}, {"id": "s3-2-e", "num": "§3.2.e", "name": "Treaty Ratification", "text": "Treaty Ratification — treaties require 2/3 Senate majority. Two sub-provisions address failed ratification: §3.2.e.i (standalone domestic provisions may proceed as ordinary legislation) and §3.2.e.ii (bilateral treaties designed as integrated wholes must be renegotiated, not disaggregated). The Nord"}, {"id": "s3-2-e-i", "num": "§3.2.e.i", "name": "Treaty Domestic Application", "text": "Where the Senate fails to ratify a treaty, if portions of the treaty's domestic provisions have standalone value independent of the international obligations, the President may transmit those portions to the House Speaker for consideration as ordinary domestic legislation. Prevents failed treaty rat"}, {"id": "s3-2-e-ii", "num": "§3.2.e.ii", "name": "Treaty Withdrawal", "text": "Where the treaty is bilateral and designed as an integrated whole — reciprocal obligations that only make sense together — the President may not disaggregate and transmit domestic provisions. The treaty must be renegotiated or abandoned. The Nordmere Cases: Case 2 applied this provision where bilate"}, {"id": "s3-2-f", "num": "§3.2.f", "name": "Impeachment Trials", "text": "Senate Electoral Functions — the Senate administers the Presidential election in the absence of a functioning Electoral Commission, presides over contested electoral proceedings, and certifies Presidential election results. A direct role in executive accountability that does not depend on the House."}, {"id": "s3-2-g", "num": "§3.2.g", "name": "Survivor Quorum — Catastrophic Casualty Events", "text": "Senate Internal Rules — the Senate defines its own internal procedures by standing order, subject to constitutional constraints. The presiding officer is the Speaker of the Senate, elected by Senate members. The Senate's procedural autonomy prevents the House from using procedural leverage to contro"}, {"id": "s3-2-h", "num": "§3.2.h", "name": "Senate Speaker Vacancy", "text": "Senate Committees — standing committees are constitutionally mandated for certain functions (the Senate Armed Services Committee for Tier 2 military authorization is the most significant). Committee composition must reflect chamber balance — no party may hold all seats on a standing committee."}, {"id": "s3-2-i", "num": "§3.2.i", "name": "Senate Amendment Authority", "text": "Senate Amendment Authority — the Senate may amend House-passed bills, but amendments must be germane to the bill's subject matter. The LI publishes a germaneness analysis before the amended bill is returned to the House. The PM must give the LI's analysis due consideration during the Legislative Rev"}, {"id": "s3-3-a", "num": "§3.3.a", "name": "Standard Passage", "text": "Standard Passage — bills pass by absolute majority of the full seated membership of both chambers, not just those present. The 'full seated membership' standard prevents passage by small quorums. Applies to ordinary legislation; higher thresholds apply to constitutional amendments, veto overrides, a"}, {"id": "s3-3-b", "num": "§3.3.b", "name": "Presidential Veto Override", "text": "Presidential Veto Override — requires 2/3 of both chambers simultaneously. The simultaneous requirement means both chambers must vote in the same session. The SC's 48-hour review under §2.1.f.i occurs before any override vote, meaning the constitutional question is settled before the political quest"}, {"id": "s3-3-c", "num": "§3.3.c", "name": "Record System Entry", "text": "Record System Entry — the presiding officer of each chamber must certify and publish the final text of every enacted law to the NRS within 24 hours. All prior versions, committee reports, Inspectorate findings, and veto records are indexed alongside the enacted text. The NRS entry is the definitive "}, {"id": "s3-3-d", "num": "§3.3.d", "name": "Legislative Mandate Enforcement", "text": "Legislative Mandate Enforcement — where the constitution requires the Legislature to enact specific legislation by statute and the Legislature fails to do so within a specified period: the LI publishes a non-compliance finding; the mandate becomes justiciable in the SC; for mandates tied to constitu"}, {"id": "s3-4", "num": "§3.4", "name": "Electoral Districts", "text": "House Redistricting — the LI conducts the census, the Legislature sets the apportionment formula, States draw their own district maps, and the LI reviews maps for compliance. The LI's review checks for partisan gerrymandering, population equality violations, and compliance with the minority protecti"}, {"id": "s3-4-a", "num": "§3.4.a", "name": "Criteria Hierarchy", "text": "Redistricting Criteria — State district maps must meet five criteria: population equality within tolerance, geographic contiguity, compliance with §1.8 non-discrimination, no intentional dilution of minority voting power, and reasonable geographic compactness. States have discretion within these bou"}, {"id": "s3-4-b", "num": "§3.4.b", "name": "Prohibited Inputs", "text": "LI Redistricting Review — the LI reviews all State-drawn district maps within 60 days of submission. If a map fails the §3.4.a criteria, the LI publishes specific findings and the State must submit a corrected map within 30 days. If the corrected map still fails, the LI draws a compliant interim map"}, {"id": "s3-4-c", "num": "§3.4.c", "name": "Drawing Authority — States", "text": "Redistricting Cycle — maps are drawn after each census, every 10 years. Emergency redistricting may occur if a State's population changes significantly between census cycles. A State may not redistrict more than once per census cycle without LI approval."}, {"id": "s3-4-d", "num": "§3.4.d", "name": "Drawing Authority — Federal Territories", "text": "Federal Territorial Districts — where federal territories elect House representatives, the Electoral Commission draws the territorial districts in consultation with the territory's governance council. Territorial districts are drawn under the same criteria that apply to State districts."}, {"id": "s3-4-e", "num": "§3.4.e", "name": "National Compliance Review", "text": "At-Large Seats — States with a small population may elect House members at-large rather than by district, if the LI determines that the minimum district size would make geographic districting meaningless. At-large elections use proportional representation mechanisms — no plurality winner-take-all at"}, {"id": "s3-4-f", "num": "§3.4.f", "name": "Court Adjudication", "text": "District Vacancy — when a House district seat falls vacant mid-term, the Electoral Commission administers a special election within 90 days. The replacement serves only the remainder of the original term. If fewer than 90 days remain in the term, the vacancy is not filled."}, {"id": "s3-4-g", "num": "§3.4.g", "name": "Continuity", "text": "Redistricting Transparency — all State submissions, LI analyses, and interim maps must be published to the NRS throughout the redistricting process. Citizens have the right to submit commentary to the LI during the review period. Redistricting decisions are judicially reviewable under §4.3."}, {"id": "s3-5", "num": "§3.5", "name": "The House — Composition and Structure", "text": "The House — the proportional chamber. Seats allocated by population, minimum one per State, floor of one per 750,000 citizens. The House originates all legislation and fiscal measures, elects the PM, and is the primary democratic accountability mechanism for the executive. Every member elected every 4 years makes it the chamber closest to current public sentiment."}, {"id": "s3-5-a", "num": "§3.5.a", "name": "House Membership Formula", "text": "House Membership Formula — seats allocated by the LI census using a formula of one seat per N citizens where N is set by statute, minimum one seat per State. Any formula producing fewer than one seat per 500,000 citizens requires published LI justification. The formula is automatic — no political negotiation of seat allocation."}, {"id": "s3-5-b", "num": "§3.5.b", "name": "House Speaker", "text": "House Speaker — elected by the House from among its members by absolute majority. Presides over House proceedings, manages the legislative calendar, and holds Acting Presidential Authority in the Presidential succession chain. The Speaker's dual role — legislative and succession — keeps the succession line within the elected legislative class."}, {"id": "s3-5-c", "num": "§3.5.c", "name": "House Vacancy", "text": "House Vacancy — a House seat that falls vacant mid-term triggers a special election within 90 days if more than 90 days remain in the term. Short-term vacancies (fewer than 90 days) are not filled — the seat remains vacant for the remainder of the term."}, {"id": "s3-5-d", "num": "§3.5.d", "name": "House Quorum", "text": "House Quorum — a majority of the full seated House membership constitutes a quorum for ordinary business. The Speaker may compel attendance of absent members by warrant. No vote that requires an absolute majority of full membership may be held without quorum."}, {"id": "s3-6-a", "num": "§3.6.a", "name": "House Expulsion", "text": "Inspectorate Access to Legislative Records — all three Inspectorates have full access to legislative records, committee deliberations, voting records, and draft legislation. The Legislature may not classify records from the Inspectorates."}, {"id": "s3-6-b", "num": "§3.6.b", "name": "Senate Expulsion", "text": "LI Pre-Passage Constitutional Review — the LI publishes a constitutional analysis of any bill that appears to conflict with a constitutional provision, before the bill reaches a final vote. Advisory, not blocking — but creates a permanent NRS record that any member voting for the bill voted with ful"}, {"id": "s3-6-c", "num": "§3.6.c", "name": "Anti-Weaponization Threshold", "text": "Committee Structure — both chambers must maintain standing committees for their constitutionally assigned functions. Committees may not be abolished while they hold a constitutional mandate. The LI audits committee operations annually."}, {"id": "s3-6-d", "num": "§3.6.d", "name": "Consequences and Restoration", "text": "Joint Sessions — the two chambers may meet in joint session for constitutionally enumerated purposes: receiving Presidential addresses, certifying election results, and voting on constitutional amendments under Path A. Joint sessions do not allow mixing of the chambers' distinct functions."}, {"id": "s3-6-e", "num": "§3.6.e", "name": "Recall — States and Territories", "text": "Ethics and Conduct — the Legislature may establish a joint ethics committee with authority to sanction, suspend (not remove), or refer members to the EI for investigation. Removal requires a 2/3 vote of the relevant chamber following a published EI finding — the ethics committee cannot remove member"}, {"id": "s3-6-f", "num": "§3.6.f", "name": "Vacancy Filling — States and Territories", "text": "Legislative Privilege — members are privileged from civil arrest and civil suit arising from acts performed in their legislative capacity: votes, speeches, committee testimony. This privilege does not extend to criminal conduct, conduct outside legislative functions, or conduct the EI has certified "}, {"id": "s3-7-a", "num": "§3.7.a", "name": "Authorization", "text": "Statutory Independent Officers — the constitution authorizes the Legislature to create independent statutory offices outside both executive domains. They exercise regulatory, quasi-judicial, or administrative functions with constitutional independence — neither executive may direct their operations."}, {"id": "s3-7-b", "num": "§3.7.b", "name": "Appointment", "text": "Registry and Nomination for Independent Officers — the JI maintains a registry of qualified candidates for each independent statutory office. The PM may only nominate from the registry. The EI reviews each nominee's disclosure record for factual accuracy before Senate confirmation. Prevents purely p"}, {"id": "s3-7-c", "num": "§3.7.c", "name": "Removal", "text": "Senate Confirmation of Independent Officers — confirmed by the Senate. Thresholds defined by the enabling statute within constitutional bounds. The Senate may not confirm an officer the EI has flagged for a material disclosure inaccuracy until the discrepancy is resolved."}, {"id": "s3-7-d", "num": "§3.7.d", "name": "Oversight", "text": "Removal of Independent Officers — removal requires a for-cause finding. The EI must publish a factual finding before any removal vote. Removal is by 2/3 of both chambers simultaneously. Neither executive may remove a statutory independent officer unilaterally."}, {"id": "s3-7-e", "num": "§3.7.e", "name": "Limits", "text": "Any citizen, State government, or parliamentary minority of 1/3 may challenge a proposed district map by petitioning the SC within the 60-day review period after LI compliance certification. The Court reviews whether criteria were correctly applied — not whether a different map would have been bette"}, {"id": "s4-1-a", "num": "§4.1.a", "name": "Establishment", "text": "The House alone may create or abolish inferior courts by statute — one of the few exclusively House powers. The Senate confirms the judges who sit on those courts (§4.1.b), but the existence and structure of the courts is a House matter. The House may also define the jurisdiction and rules of inferi"}, {"id": "s4-1-b", "num": "§4.1.b", "name": "Appointment of Inferior Courts", "text": "PM nominates within 90 days; the Senate confirms by a supermajority (55–67% of full seated membership). Senate confirmation corrected from House in v157. Four sub-provisions now numbered §4.1.b.i–iv: (i) Candidate Disclosure and EI Review — PM submits disclosure record to EI before confirmation vote"}, {"id": "s4-1-c", "num": "§4.1.c", "name": "Judicial Tenure Protection", "text": "Judicial Tenure Protection — inferior court judges, once commissioned, serve during good behavior with no fixed term. The Legislature may establish a maximum service age or maximum total service period (not less than 15 years from first commissioning), but may not create fixed-term appointments shor"}, {"id": "s4-1-d", "num": "§4.1.d", "name": "Judicial Removal", "text": "Judicial Removal — three tracks: legislative removal by 2/3 of both chambers for constitutional breach or demonstrated incapacity; judicial discipline through the SC's internal accountability process; and criminal conviction for disqualifying offenses. The EI must publish a factual finding before an"}, {"id": "s4-2", "num": "§4.2", "name": "Open-Candidacy Judicial Selection", "text": "The SC selection system: fully open candidacy, advisory expert assessment, and national direct election by Ranked Choice Vote. No political branch nominates anyone. The Registry is the eligibility filter, the Judicial Selection Board is the expert voice, and the electorate makes the final determinat"}, {"id": "s4-2-a", "num": "§4.2.a", "name": "Candidate Registration", "text": "Candidate Registration — any citizen on the SC Candidate Registry (maintained by the JI under §8.4.e) may stand by filing a full disclosure record with the EI. The EI reviews within 14 days for factual accuracy — not to assess the quality of credentials. A candidate with a material inaccuracy is rem"}, {"id": "s4-2-b", "num": "§4.2.b", "name": "Judicial Selection Board", "text": "Judicial Selection Board — five senior judges (at least 10 years continuous service) chosen by lot by the JI from all eligible judges who are not themselves candidates. Advisory assessment of every candidate's judicial record, legal reasoning, and professional independence. Advisory only — no ballot"}, {"id": "s4-2-c", "num": "§4.2.c", "name": "Judicial Inspectorate Certification", "text": "JI Certification — the JI confirms that each candidate remains on the SC Candidate Registry and that no disqualifying change has occurred since Registry admission. Ministerial check, not a new assessment. Candidates who fail JI certification may appeal to an Appellate Court within 14 days."}, {"id": "s4-2-d", "num": "§4.2.d", "name": "Public Election", "text": "The Election — national RCV election administered by the Electoral Commission. All JI-certified candidates appear on the ballot. Winner achieves a national RCV majority. The EC certifies the result; the elected justice takes the Official Oath. Recorded on the NRS within 24 hours. From this moment, t"}, {"id": "s4-2-e", "num": "§4.2.e", "name": "Mid-Term Vacancies", "text": "Mid-Term Vacancies — any vacancy triggers a special election within 180 days. The full open-candidacy process applies with compressed timelines: registration Day 30, EI review Day 60, Board assessment Day 90, JI certification Day 120, election Day 180. The replacement serves only the remainder of th"}, {"id": "s4-2-f", "num": "§4.2.f", "name": "Emergency Panel for Tier 1 Scope Challenges", "text": "Emergency Panel — four justices drawn by rotation each 2-year cycle. Sole jurisdiction over constitutional challenges to Tier 1 presidential military authority during active operations. Must rule within 48 hours. Binding on the full Court unless overruled within 72 hours. Ensures SC oversight during"}, {"id": "s4-2-g", "num": "§4.2.g", "name": "Vacancy Operating Rules", "text": "Temporary Associate Justice — the most senior Appellate Court judge by continuous service is automatically designated as Temporary Associate Justice within 5 days of any SC vacancy, without nomination or confirmation. Full vote in all cases. Cannot stand as a candidate for the seat they are temporarily filling. Ensures the SC always has nine participating justices. For purposes of this provision, \"continuous service\" means uninterrupted judicial commission without a break exceeding 90 days, calc"}, {"id": "s4-2-h", "num": "§4.2.h", "name": "Judicial Recusal", "text": "Class Assignment and Stagger — at Phase 3, all nine seats are filled simultaneously, then assigned to three classes by public lot drawn by the JI. Class A: 4-year initial term. Class B: 8-year initial term. Class C: 12-year initial term. All subsequent terms: 12 years. The lot assignment is publishe"}, {"id": "s4-3-a", "num": "§4.3.a", "name": "Concrete Cases Only", "text": "Judicial Review — the SC (and inferior courts within their jurisdictions) has authority to declare legislative acts, executive orders, and administrative decisions unconstitutional and void. No political actor may override a constitutional ruling. The SC identifies the constitutional defect; the Leg"}, {"id": "s4-3-b", "num": "§4.3.b", "name": "Organizational Standing", "text": "Judicial Scope — courts decide constitutional questions, not policy questions. The SC may not substitute its judgment for the Legislature's on policy matters — it may only determine whether the Legislature acted within its constitutional authority. A statute that is constitutionally permissible but "}, {"id": "s4-3-c", "num": "§4.3.c", "name": "Ripeness and Mootness", "text": "Administrative and Statutory Interpretation — courts apply statutes to specific cases and resolve ambiguities. Where a statute is ambiguous, courts apply the interpretation most consistent with the constitution. Courts may not rewrite clear statutory language to produce a preferred outcome — they in"}, {"id": "s4-3-d", "num": "§4.3.d", "name": "Original Jurisdiction", "text": "Original Jurisdiction — the SC has original (first-instance) jurisdiction over constitutional disputes between States, between a State and the federal government, and over challenges to the constitutional validity of a federal statute brought within 90 days of enactment. Certain cases bypass all low"}, {"id": "s4-3-e", "num": "§4.3.e", "name": "Inspectorate Findings in Constitutional Proceedings", "text": "Inspectorate Findings — NRS findings published by the LI, EI, or JI are admissible as authoritative factual evidence in judicial proceedings. Courts must address any inconsistency between their factual findings and a prior Inspectorate finding in written decisions. Inspectorate findings are not judi"}, {"id": "s4-4-a", "num": "§4.4.a", "name": "Judicial Judgments", "text": "Non-recognition grounds are exhaustive: the issuing court lacked jurisdiction; the judgment was obtained by fraud; enforcement would require an act the Legislature has defined as categorically unenforceable. A fourth ground — facially contrary to Article I — was removed as redundant. §15.6 Constitut"}, {"id": "s4-4-b", "num": "§4.4.b", "name": "NRS Authentication", "text": "NRS Authentication — a judgment, order, or status record published to the NRS is self-authenticating in any other State or Territory court. No re-certification, notarization, or further authentication required. Eliminates the multi-state authentication burden that historically delayed enforcement of"}, {"id": "s4-4-c", "num": "§4.4.c", "name": "Public Acts and Official Records", "text": "Official records on the NRS are self-authenticating — no re-certification required. Professional licenses receive equivalent recognition across all States and Territories. The Legislature latitude language previously allowing the Legislature to define the \"permissible scope\" of supplementary require"}, {"id": "s4-4-d", "num": "§4.4.d", "name": "Status Orders — Special Protections", "text": "Status Orders — protective orders, custody determinations, and other status orders take immediate effect in every State and Territory upon publication to the NRS. No waiting period, no local re-registration. Tested directly in Everywhere She Goes — a protective order followed the holder across State"}, {"id": "s4-4-e", "num": "§4.4.e", "name": "Limits — No Obligation Beyond Republic Borders", "text": "Non-Discrimination in Recognition — a State or Territory may not discriminate in its recognition of another jurisdiction's judgments or records based on the nature of the parties, the subject matter, or the legal status recognized by the issuing jurisdiction. Recognition is mandatory; non-recognitio"}, {"id": "s4-4-f", "num": "§4.4.f", "name": "Legislative Implementation Mandates", "text": "Finality rule is now permanent rather than a default pending legislation. A judgment is final for §4.4.a purposes if it is not subject to an automatic stay under the issuing jurisdiction's procedural law, regardless of whether an appeal is pending. The Legislature may refine the finality standard fo"}, {"id": "s5-1-a", "num": "§5.1.a", "name": "Inherent Citizenship", "text": "A child is automatically a citizen at birth if at least one parent is a Citizen or Legal Resident at the time of birth. Statelessness prevention clause: where a child would otherwise be stateless, citizenship is granted regardless of parental status. No citizenship may be stripped from a natural-bor"}, {"id": "s5-1-a-i", "num": "§5.1.a.i", "name": "Statelessness Prevention", "text": "A child born on Republic territory to parents holding neither Citizen nor Legal Resident status is an Inhabitant from birth, with full Article I protections and BNF access. Where no country recognizes the child as a citizen, the Republic provides a determination process consistent with §6.4's protection principles — protection first, determination second. A child determined to hold no other citizenship is eligible for Legal Residency from birth, with all Inhabitant years counting toward the §5.1"}, {"id": "s5-1-b", "num": "§5.1.b", "name": "Coming of Age", "text": "Children of citizens are Inhabitants at birth with full Article I protections. Full citizenship rights — including the right to vote — activate at 18. The distinction between Inhabitant and Citizen status for citizen children prevents citizenship from being used to exempt children from local law."}, {"id": "s5-1-c", "num": "§5.1.c", "name": "Naturalization", "text": "A Legal Resident may earn citizenship after five continuous years of residency, passing the Constitutional Logic Test, and demonstrating a working knowledge of the Republic's official language. "}, {"id": "s5-1-d", "num": "§5.1.d", "name": "National Service Path", "text": "A Legal Resident may earn citizenship through honorable completion of military or national service — a service path that runs parallel to the residency path. Years of service are a legitimate basis for constitutional membership."}, {"id": "s5-1-e", "num": "§5.1.e", "name": "Citizenship Irrevocability", "text": "Citizenship "}, {"id": "s5-1-f", "num": "§5.1.f", "name": "Derivative Status", "text": "A child born before a parent acquired Legal Residency or Citizenship, who accompanies that parent to the Republic within a Legislature-defined window, receives derivative status. Prevents a parent's pre-Republic legal status from permanently cutting off their child's path to citizenship."}, {"id": "s5-1-g", "num": "§5.1.g", "name": "Accelerated Naturalization — Long-Term Pre-Ratification Residents", "text": "Any person who resided continuously in the Republic's territory for 5+ years immediately before Day Zero but did not hold predecessor voting rights — including persons disenfranchised by laws subsequently nullified under §19.2 — may apply for citizenship through an accelerated process the Legislatur"}, {"id": "s5-2", "num": "§5.2", "name": "Legal Resident Rights", "text": "Legal Residents hold a Residency Credential allowing them to work, enter contracts, own property, access BNF programs, and participate in local elections where the Legislature authorizes. They hold all Article I rights as Inhabitants. What they lack that citizens hold: federal voting rights and the "}, {"id": "s5-3", "num": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. "}, {"id": "s5-4", "num": "§5.4", "name": "The Constitutional Logic Test", "text": "The CLT is required for earned citizenship through naturalization (§5.1.c) and national service (§5.1.d). It tests knowledge of constitutional principles and civic structure — not political opinions or cultural loyalty. The Senate deadlock rule (§5.4.c) ensures the existing test remains in force if "}, {"id": "s5-4-a", "num": "§5.4.a", "name": "Senate Authority over the CLT Standard", "text": "The constitutional floor is stated directly in §5.4: the test must assess knowledge sufficient to understand the structure, powers, limits, and rights established by this Constitution. Any statute reducing the CLT below this floor is void and any citizen may challenge it in court. The Senate sets the standard by statute — raising it by simple majority, lowering it by 2/3 supermajority. That asymmetry makes degradation structurally harder than improvement without requiring anyone to certify anyth"}, {"id": "s5-4-b", "num": "§5.4.b", "name": "CLT Administrator", "text": "The Constitutional Logic Test is administered by a CLT Administrator nominated by the PM from a Candidate Register, confirmed by the Senate. Structural independence from partisan influence: the CLT process cannot be used to create barriers that track political outcomes."}, {"id": "s5-4-c", "num": "§5.4.c", "name": "Status Quo Maintenance", "text": "Senate deadlock on CLT standard changes keeps the existing version in force. Deadlock cannot be weaponized to eliminate the CLT or make it impossibly difficult — the existing test remains operative."}, {"id": "s5-5-a", "num": "§5.5.a", "name": "Automatic Citizenship Grant", "text": "All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship without testing or application. The Day Zero Grandfather Clause prevents the new Republic from immediately disenfranchising its existing population by requiring existing voters to re-qualify "}, {"id": "s6-1-ab", "num": "§6.1.a–b", "name": "The Dual Gate", "text": "Legal residency requires passing both gates. Gate 1 is the federal substantive assessment — national standards that no State can circumvent. Gate 2 is State acceptance — no State can be forced to absorb unlimited immigration obligations without its participation. The dual-gate architecture prevents "}, {"id": "s6-1", "num": "§6.1", "name": "The Dual-Gate System", "text": "Every immigration application must clear two sequential gates: Gate 1 (state sponsorship) and Gate 2 (federal certification). The Legislature holds supreme authority over immigration — it sets the standards for both gates and may set aggregate limits on total applications processed in any period, pr"}, {"id": "s6-1-a", "num": "§6.1.a", "name": "Gate 1 — State Sponsorship", "text": "A sponsoring State certifies the applicant through its own vetting process and accepts notification obligations during the application period. During the application period the applicant must maintain a genuine connection to the sponsoring State — as the Legislature defines by statute — so that noti"}, {"id": "s6-1-b", "num": "§6.1.b", "name": "Gate 2 — Federal Certification", "text": "Federal certification across four statutory categories: identity verification, criminal history, national security assessment, self-sufficiency or support guarantee. Cannot impose ideological screening or nationality-based quotas. Any denial must specify the precise ground in writing. National secur"}, {"id": "s6-1-c", "num": "§6.1.c", "name": "Presidential Role", "text": "Once an applicant clears both gates, the President must ministerially issue residency credentials. The word 'ministerially' is deliberate — the President has no discretion to refuse or delay what the law requires. Presidential interference with credential issuance is constitutionally prohibited."}, {"id": "s6-1-d", "num": "§6.1.d", "name": "Federal Sponsorship Category", "text": "The Legislature may establish a Federal Sponsorship Category where designated federal agencies serve as Gate 1 sponsors for applicants whose skills directly serve a defined federal interest — research programs, national infrastructure, national security-adjacent technical roles. The agency assumes a"}, {"id": "s6-2", "num": "§6.2", "name": "Enforcement and Removal", "text": "Only the federal government may remove individuals from the Republic — States may not conduct deportations independently. This prevents States from developing parallel immigration enforcement regimes that could be used to target populations the State government dislikes regardless of federal law. Re"}, {"id": "s6-3", "num": "§6.3", "name": "Gate 2 Appeal Rights", "text": "Gate 2 denials are judicially challengeable on three grounds: criterion outside the four certified categories; denial made on discriminatory grounds contrary to §1.8; or procedural violation affecting the outcome. Gate 1 denials — a state's decision not to sponsor — are not subject to federal review"}, {"id": "s6-3-a", "num": "§6.3.a", "name": "Judicial Challenge", "text": "An applicant may challenge a Gate 2 denial on three grounds: criterion outside the four certified categories; discriminatory application; or procedurally deficient process. Three-ground limitation channels challenges rather than eliminating them."}, {"id": "s6-3-b", "num": "§6.3.b", "name": "National Security Denials — In-Camera Review", "text": "Where Gate 2 is denied on national security grounds, a reviewing court may examine the classified assessment in camera and determine whether it constitutes a credible, specific, and documented concern — without publishing classified content. The in-camera review is outcome-determinative: either the "}, {"id": "s6-4", "num": "§6.4", "name": "Asylum and Protection", "text": "Asylum proceedings operate on a separate constitutional track from the dual-gate immigration system. An asylum filer under §1.27 becomes an Inhabitant at filing — not upon grant. Their claim must be determined before any removal order takes effect. The asylum track is explicitly exempt from Gate 1 s"}, {"id": "s6-4-a", "num": "§6.4.a", "name": "Asylum Seekers as Inhabitants", "text": "Any person who files an asylum claim under §1.27 is an Inhabitant of the Republic from the date of filing — immediately entitled to BNF coverage and all Article I protections. Protection-first: the determination process does not happen in a rights-free zone."}, {"id": "s6-4-b", "num": "§6.4.b", "name": "Right to Determination and Protection During Proceedings", "text": "Asylum proceedings must provide: a qualified adjudicator with decision authority, access to an interpreter, the right to present evidence and witnesses, a written decision specifying grounds, and a right of appeal. Standards apply regardless of the applicant's point of entry into the Republic."}, {"id": "s6-4-c", "num": "§6.4.c", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges hold full tenure protections. The Legislature may not establish any asylum determination body as a subdivision or instrumentality of either executive branch — "}, {"id": "s6-4-d", "num": "§6.4.d", "name": "Non-Penalization for Irregular Entry", "text": "The manner or means of entry into the Republic — including irregular or unauthorized entry — does not affect the right to claim asylum or have that claim determined. No penalty arising solely from irregular entry may be imposed on a person whose asylum claim is pending or has been granted."}, {"id": "s6-4-e", "num": "§6.4.e", "name": "Unexecutable Removal Orders", "text": "Legislature must define a minimum status, material conditions, and periodic judicial review for persons subject to final removal orders that cannot be executed — because the destination country won't accept them, or execution would violate §1.27. The constitution does not allow indefinite stateless "}, {"id": "s6-4-f", "num": "§6.4.f", "name": "Security and Criminal Protection Cases", "text": "Where the Asylum Court grants §1.27 protection to a person who poses a documented security threat, removal remains constitutionally barred — but indefinite unreviewed detention is not constitutionally available. The Legislature must establish a framework with regular judicial review. 'Indefinite unreviewed detention is not a constitutionally available outcome' — one of the clearest lines in the document. Where removal is barred under §1.27 and a documented security threat is established, the Rep"}, {"id": "s6-4-g", "num": "§6.4.g", "name": "Territory Accessibility", "text": "The asylum proceedings statute must ensure asylum is accessible to persons in Territories and geographically remote areas — not just major population centers. The right to seek asylum applies regardless of where in the Republic a person arrives."}, {"id": "s6-4-h", "num": "§6.4.h", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic or presenting to Republic authorities is an Inhabitant from the moment of contact and holds full §1.27 protection. A federal legal guardian must be appointed within 24 hours. No unaccompanied minor may be detained in a facility not specifically designa"}, {"id": "s7-1", "num": "§7.1", "name": "Standard Elections — Ranked Choice", "text": "All federal elections on National Election Day, every two years. All elections for House, Senate, SC, and Electoral Commission seats use Ranked Choice Voting — majority required, not plurality. No federal elections outside National Election Day except special elections for vacancies. This concentrat"}, {"id": "s7-2-a", "num": "§7.2.a", "name": "National Ranked-Choice Vote", "text": "Presidential elections use RCV nationally, preventing the geographic distortions of district-based winner-take-all systems. Votes transfer until one candidate holds a majority of active ballots nationwide. The national RCV tends to produce presidents who are the genuine second or third choice of a l"}, {"id": "s7-2-b", "num": "§7.2.b", "name": "The Combined Score", "text": "Where no candidate achieves a national RCV majority, the combined score mechanism favors the candidate with the broadest geographic distribution of support. A candidate who wins large margins in a few populous regions but has near-zero support elsewhere represents a fundamentally different governing"}, {"id": "s7-2-c", "num": "§7.2.c", "name": "Presidential Election Regions", "text": "Presidential election regions provide the geographic breadth component of the combined score, ensuring that a winning candidate builds support across the Republic's geographic spread rather than only its population centres. The number of regions is defined by the Legislature by statute. Regions are "}, {"id": "s7-2-c-i", "num": "§7.2.c.i", "name": "State Candidate Pools", "text": "Each State maintains a standing Regional Boundary Pool for each redistricting cycle. Any person may be placed into a State's Pool through the State's own constitutional or statutory process, provided they meet three eligibility requirements at the time of entry: at least five continuous years of Rep"}, {"id": "s7-2-c-ii", "num": "§7.2.c.ii", "name": "Annual Addition Cap", "text": "Each State may add no more than five entrants to its Pool per calendar year during the pool-building period. Unused addition slots do not carry forward; a year with fewer than five additions simply has fewer, and unused capacity is permanently lost. If a pool member dies, becomes permanently incapac"}, {"id": "s7-2-c-iii", "num": "§7.2.c.iii", "name": "Pool Health Monitoring", "text": "The LI monitors each State's Pool and publishes an annual Pool Status Report to the NRS. If any State's Pool falls below five eligible entrants, the LI publishes a Pool Health Notice — advisory, not compulsory. If a State's Pool is entirely empty at the time of the draw, that State's commission seat"}, {"id": "s7-2-c-iv", "num": "§7.2.c.iv", "name": "Commission Constitution", "text": "Following each decennial census, the JI constitutes the Regional Boundary Commission by public lottery, drawing one name by lot from each State's eligible Pool. The draw is held in a single public session witnessed by a representative of each Inspectorate and three citizens selected by jury protocols, and certified jointly by all three Inspectorates. The session may be conducted remotely under parameters set by statute; remote participation does not affect validity. The full draw is recorded to the NRS in real time. One member per State; no political substitution. Replacements drawn from the same State's Pool."}, {"id": "s7-2-c-v", "num": "§7.2.c.v", "name": "Commission Compensation", "text": "Commission members are compensated by their State for days in active session only. Service on the commission is temporary and session-based; no retainer, salary, or ongoing compensation is provided outside of active session days. The federal government reimburses each State for session compensation "}, {"id": "s7-2-c-vi", "num": "§7.2.c.vi", "name": "Drawing Criteria", "text": "Regional boundaries must meet the following criteria in order of precedence: (1) Population balance — broadly equal citizen population within a Legislature-defined tolerance. (2) Geographic contiguity — each region must be a single contiguous territory. (3) Non-discrimination — no region may dilute "}, {"id": "s7-2-c-vii", "num": "§7.2.c.vii", "name": "Drawing Process and Timeline", "text": "Commission must submit proposed regional map to LI within 180 days of constitution. Operates by simple majority vote. 30-day public comment period; commission must publish written response before final submission. Legislature sets by statute the parameters under which the commission conducts working sessions: remote participation authorization, quorum and voting requirements, secure platform and data access specifications. Legislature may not set parameters that prevent effective deliberation or impose undue burden on members. Commission remains constituted until final map certified, then dissolves."}, {"id": "s7-2-c-viii", "num": "§7.2.c.viii", "name": "LI Compliance Review", "text": "The LI reviews the submitted map within 60 days for compliance with the §7.2.c.vi criteria. If compliant, the LI certifies it and publishes the certification to the NRS. If the map fails, the LI publishes specific findings and returns it to the commission, which has 30 days to submit a corrected map"}, {"id": "s7-2-c-ix", "num": "§7.2.c.ix", "name": "Judicial Review", "text": "Any citizen, State government, or parliamentary minority of one-third may challenge a certified regional map by petitioning the Supreme Court within 60 days of LI certification. The Court reviews criteria application — not map preference. A successful challenge returns the map to the commission with"}, {"id": "s7-2-c-x", "num": "§7.2.c.x", "name": "Cycle and Timing", "text": "Regional boundaries are redrawn following each decennial census, on the same cycle as House redistricting; the §8.1.a census triggers both simultaneously. Regions in effect at the time of any presidential election govern that election. No mid-cycle redraw may occur except pursuant to §7.2.c.ix or §7"}, {"id": "s7-2-d", "num": "§7.2.d", "name": "Territory Presidential Voting", "text": "Territory citizens hold the full §1.19 right to vote in presidential elections. Their votes count in the "}, {"id": "s7-2-e", "num": "§7.2.e", "name": "Election Certification", "text": "The Electoral Commission certifies the final presidential election result to the NRS within a period the Legislature defines by statute. Certification is final and may be challenged only before the Supreme Court within 14 days. No transfer of presidential authority may be delayed beyond the constitu"}, {"id": "s7-2-f", "num": "§7.2.f", "name": "Run-off", "text": "If two candidates are within 0.5 percentage points of each other on the final combined score as calculated under §7.2.b, a head-to-head national RCV runoff is conducted between those two candidates. The runoff closes the edge-case gap where the combined score is mathematically indeterminate."}, {"id": "s7-3-a", "num": "§7.3.a", "name": "No Executive Interference", "text": "The President may not declare, postpone, or influence the scheduling of elections — including declaring emergencies that have the effect of postponing them. §1.25.e's prohibition on emergency-based election postponement backs this up: even a genuine emergency cannot defer a scheduled election."}, {"id": "s7-3-b", "num": "§7.3.b", "name": "National Voting System", "text": "The Electoral Commission administers the National Voting System through which all federal elections and referenda are conducted. The NVS is constitutionally required to maintain ballot secrecy, public auditability, and resilience — properties defined in Article XVI creating a cross-constitutional gu"}, {"id": "s7-3-c", "num": "§7.3.c", "name": "Participation Protection", "text": "No State may take any action that reduces NVS access, functionality, or availability within its territory. State-level voter suppression — long lines, ID requirements that function as bars, polling place closures that reduce access — is constitutionally prohibited to the extent it reduces access for"}, {"id": "s8-1", "num": "§8.1", "name": "Three Inspectorates", "text": "The Three Inspectorates — one for each branch, each selected by the branches it does not watch. Constitutional independence, information-only mandate (§8.6), 10-year non-renewable terms, funding floors. No government majority can defund, direct, or suppress them without a 2/3 supermajority."}, {"id": "s8-1-a", "num": "§8.1.a", "name": "The Legislative Inspectorate (LI)", "text": "LI Mandate — audits the Legislature for fiscal accuracy, constitutional compliance, and NRS integrity. Conducts the population census (assigned to the LI because the census determines House seat allocation — giving this to a body nominated by the House would be a direct conflict of interest). Review"}, {"id": "s8-1-b", "num": "§8.1.b", "name": "The Executive Inspectorate (EI)", "text": "EI Mandate — audits both executives and the Monetary Authority. Annual military compliance assessment: were Tier authorizations followed? Was §1.29.d Intelligence Firewall maintained? Were fund certifications observed? Publishes clemency background reports before any executive act. Reviews disclosur"}, {"id": "s8-1-c", "num": "§8.1.c", "name": "The Judicial Inspectorate (JI)", "text": "JI Mandate — audits the courts for judicial scope and independence. Maintains the SC Candidate Registry. Vets judicial nominees and Electoral Commission candidates. Screens citizen referendum petitions for eligibility. Audits the Electoral Commission annually. Reviews accommodation compact complianc"}, {"id": "s8-2", "num": "§8.2", "name": "Selection and Independence", "text": "Selection and Independence — the cross-nomination model. SC nominates the LI IG (confirmed by Senate 2/3; House entirely excluded). House nominates the EI IG (confirmed by Senate simple majority; JI vets). JI IG selected by public lottery (no political body nominates anyone). Each Inspectorate is st"}, {"id": "s8-3-a", "num": "§8.3.a", "name": "Legislative IG", "text": "LI Inspector General Selection — nominated by the Supreme Court, confirmed by the Senate by 2/3 supermajority. The House is entirely excluded — the body whose seat allocation the census determines has no role in selecting the office that conducts the census. The 2/3 Senate threshold ensures the LI I"}, {"id": "s8-3-b", "num": "§8.3.b", "name": "Executive IG", "text": "EI Inspector General Selection — nominated by the House, confirmed by the Senate by simple majority, with JI vetting of the nominee's disclosure record before the confirmation vote. The House nominates the EI because the PM — whom the EI watches — is accountable to the House, creating structural ali"}, {"id": "s8-3-c", "num": "§8.3.c", "name": "Term and Staggering", "text": "Term and Staggering — all IGs serve 10-year non-renewable terms. No two IG terms may begin within 18 months of each other, ensuring continuous institutional knowledge. An outgoing IG may not be reappointed to the same office. The stagger means the system never faces simultaneous turnover in multiple"}, {"id": "s8-4-a", "num": "§8.4.a", "name": "Judicial IG Candidate Pool", "text": "JI IG Selection — drawn by public lottery from a qualified candidate pool. The outgoing JI IG administers the draw, witnessed by the other two IGs and three citizens chosen by jury protocols. Published to the NRS immediately. No political body nominates the JI IG — the most structurally independent "}, {"id": "s8-4-b", "num": "§8.4.b", "name": "JI Compact Compliance Audit", "text": "JI Compact Compliance — annual compliance reviews for §19.1 accommodation compacts, Article XX Associated Community compacts, and Article XIV indigenous compact obligations. The JI verifies that Article I rights protections are being maintained and that compact terms are being honored by both parties."}, {"id": "s8-4-c", "num": "§8.4.c", "name": "JI Court Operations Audit", "text": "JI Court Operations Audit — annual audit of the court system for judicial scope compliance, independence from political pressure, and proper administration of judicial functions. The JI does not audit judicial reasoning — it audits whether courts are operating within their constitutional mandate and free from inappropriate influence."}, {"id": "s8-4-d", "num": "§8.4.d", "name": "JI Electoral Commission Audit", "text": "JI Electoral Commission Audit — annual audit of the EC for electoral integrity compliance, administrative accuracy, and independence. Distinct from the EI's executive compliance audit — the JI focuses on electoral administration integrity. Published to the NRS as a standalone annual report."}, {"id": "s8-4-e", "num": "§8.4.e", "name": "Supreme Court Candidate Registry", "text": "SC Candidate Registry — the JI maintains the standing registry from which SC candidates are drawn. Any citizen meeting the eligibility criteria (15+ years legal practice or 10+ years judicial service, no current government position, no disqualifying financial interest) may apply. Applications review"}, {"id": "s8-5-a", "num": "§8.5.a", "name": "For-Cause Removal", "text": "For-Cause Removal of IGs — requires 2/3 of both chambers simultaneously, preceded by a State Designee Panel finding under §8.9.f. The Panel verification requirement prevents politically motivated removal — the Legislature may not vote on For-Cause removal of an IG without a Panel finding on the stated grounds. The Legislature may proceed to the vote regardless of the direction of the Panel's finding; the finding becomes permanent public record alongside the vote."}, {"id": "s8-5-b", "num": "§8.5.b", "name": "No-Cause Removal", "text": "No-Cause Removal — any IG may be removed without cause by 3/4 of both chambers simultaneously, except the Judicial Inspectorate IG under §8.5.c, whose lottery-based selection makes no-cause removal equivalent to a political veto over the draw result. The higher threshold (3/4 vs 2/3 for cause) ensures no-cause removal is used only when extraordinary circumstances make continued service untenable regardless of conduct."}, {"id": "s8-5-c", "num": "§8.5.c", "name": "Judicial IG — For-Cause Only", "text": "JI Removal — the JI IG may only be removed for cause; no-cause removal is not available. The JI's lottery-based selection and its role in judicial independence oversight makes it the most insulated of the three offices."}, {"id": "s8-6-a", "num": "§8.6.a", "name": "Reports", "text": "The Information-Only Mandate — Inspectorates publish facts; they do not issue binding orders or legal determinations. A finding that a government actor has breached the constitution is a factual statement, not a judgment. Courts, the Legislature, and the People decide what to do with those facts. Th"}, {"id": "s8-6-b", "num": "§8.6.b", "name": "No Classification", "text": "NRS Publication — every Inspectorate finding, report, and discrepancy notice must be published to the NRS permanently and free of charge. No official may suppress, delay, classify, or alter an Inspectorate Report before publication. The publication requirement is absolute."}, {"id": "s8-6-c", "num": "§8.6.c", "name": "No Binding Force", "text": "Minority Reports — any staff member may publish a Minority Report directly to the NRS if they believe a finding has been improperly omitted or suppressed by the IG. Staff cannot be disciplined for filing a Minority Report — the protection is absolute. Creates an internal whistleblower mechanism with"}, {"id": "s8-6-d", "num": "§8.6.d", "name": "Non-Pursuit Disclosure", "text": "Classification Exemption — Inspectorate Reports are permanently exempt from classification. If an investigation involves classified material, the Report describes the issue's nature without reproducing classified content and flags it for the relevant executive. The classification exemption is one of"}, {"id": "s8-6-e", "num": "§8.6.e", "name": "Minority Reports", "text": "Annual State of the Republic Report — the three Inspectorates jointly publish an annual report on a constitutionally fixed date, regardless of whether any political actor requests it. Covers compliance rates, investigation summaries, constitutional strains, and a forward-looking risk register. No go"}, {"id": "s8-6-f", "num": "§8.6.f", "name": "Inspectorate Funding Guarantee", "text": "Joint Investigation Authority — where a compliance question spans multiple Inspectorate mandates, the Inspectorates may conduct a joint investigation. Joint findings are published as a combined report. Neither IG may veto the other's contribution to a joint finding."}, {"id": "s8-6-g", "num": "§8.6.g", "name": "Citizen Discrepancy Petition", "text": "Investigative Access — all three Inspectorates have unrestricted access to records, personnel, facilities, and systems within their audit mandate. No official may obstruct, delay, or impede an Inspectorate investigation. Obstruction is a constitutional breach reportable by the affected Inspectorate "}, {"id": "s8-7", "num": "§8.7", "name": "Triggered Investigations", "text": "EI Dereliction Investigation — the EI may investigate a constitutional officer for dereliction: failure to perform a constitutionally mandated function. Dereliction is distinct from breach — breach is doing something unconstitutional, dereliction is failing to do something constitutionally required."}, {"id": "s8-7-a", "num": "§8.7.a", "name": "Official Trigger", "text": "Dereliction Standards — dereliction requires: (a) the constitutional function is clearly established; (b) the officer failed to perform it within the constitutionally required period; and (c) the failure was not caused by circumstances genuinely beyond the officer's control. Political disagreement w"}, {"id": "s8-8-b", "num": "§8.8.b", "name": "Publication", "text": "EI Annual Military Assessment — a dedicated section within the EI's annual report covering: whether military operations in the prior year were authorized through the correct Tier; whether the §1.29.d Intelligence Firewall was maintained; whether PM fund certifications were obtained and observed; whe"}, {"id": "s8-4-f", "num": "§8.4.f", "name": "JI Judicial Independence Audit", "text": "JI Judicial Independence Audit — annual published audit of the entire court system. The JI audits the independence of the process, not judicial reasoning or outcomes: are judges free from political pressure? Are proper recusal procedures being followed? Are ex parte communications being reported? Are court appointments following constitutional processes?"},
  {"id": "s8-4-g", "num": "§8.4.g", "name": "SC Independence Assessment", "text": "SC Independence Assessment — within the annual judicial audit, the JI publishes a specific assessment of SC independence: the integrity of the SC election process; any attempts to influence SC candidates before election; any contacts between SC justices and political actors not disclosed to the NRS; the adequacy of the SC's internal disclosure protocols."},
  {"id": "s8-4-h", "num": "§8.4.h", "name": "Inferior Court Compliance", "text": "Inferior Court Compliance — the JI audits inferior courts for compliance with their jurisdictional limits under §4.3.b. Courts that repeatedly exceed their jurisdictional scope, or demonstrate a pattern of failing to apply constitutional standards, are flagged in the JI annual report. The JI identifies systemic compliance issues for legislative or SC attention."},
  {"id": "s8-4-i", "num": "§8.4.i", "name": "Gatekeeping Appeal", "text": "Gatekeeping Appeal — any candidate removed from a ballot by the JI's certification function may appeal to the Appellate Court within 14 days. The Court reviews only whether the JI correctly applied the eligibility criteria. Must rule within 21 days. If the removal is found improper, the candidate is reinstated to the ballot."},
  {"id": "s8-9", "num": "§8.9", "name": "State Designee Panel", "text": "The State Designee Panel is a verification body constituted per proceeding whose sole constitutional function is to assess, prior to any qualifying For-Cause removal vote by the Legislature, whether the stated grounds for removal are substantiated within the enumerated constitutional categories. The Panel publishes a binary finding — grounds substantiated or grounds unsubstantiated — and the Legislature may proceed to any removal vote regardless of the finding's direction. The Panel has no investigative authority and no institutional presence outside of active proceedings."},
  {"id": "s8-9-a", "num": "§8.9.a", "name": "State Designee Pools", "text": "Each State maintains a standing State Designee Pool. Eligibility at time of entry: five continuous years of Republic citizenship; no current or recent federal office (within three years); no pending federal criminal proceedings; no current Panel service. Pool membership is a public record on the NRS. A member whose position is extinguished upon completing service may be re-added by their State within the annual addition cap."},
  {"id": "s8-9-b", "num": "§8.9.b", "name": "Annual Addition Cap", "text": "Each State may add no more than five entrants to its Pool per calendar year. Unused addition slots do not carry forward. A member who withdraws, becomes ineligible, or is drawn to serve has their position extinguished and not replaced outside the normal annual addition process."},
  {"id": "s8-9-b-i", "num": "§8.9.b.i", "name": "Mandatory State Designation", "text": "If the national pool falls below thirty eligible members at proceeding activation, or any State has made zero additions for three or more consecutive years and its pool contains fewer than two eligible members, the JI issues a Mandatory Designation Notice. Each notified State must designate one eligible person within ten days. Designated persons must meet all §8.9.a eligibility requirements — mandatory designation does not lower the standard. Mandatory designations are not subject to the annual cap and do not consume a voluntary slot. Failure is a constitutional compliance failure flagged by the LI and published to the NRS. EI assumes oversight when an LI IG removal proceeding is the triggering event."},
  {"id": "s8-9-c", "num": "§8.9.c", "name": "Pool Monitoring", "text": "The LI monitors each State's Pool and publishes an annual Pool Status Report to the NRS. Pool Health Notice if a State's pool falls below two eligible members — advisory only. Emergency session required if the combined national pool falls below twenty eligible members at the time any proceeding is activated. EI assumes monitoring duties during active LI IG removal proceedings."},
  {"id": "s8-9-d", "num": "§8.9.d", "name": "Panel Constitution", "text": "Upon activation of a qualifying proceeding, the JI constitutes the Panel by public lottery within five days. Draws five members plus two alternates from the combined national pool, in a session certified jointly by all three Inspectorates. Session may be conducted remotely under statute. Drawn members must accept or decline within 48 hours; declines filled by alternates. Panel dissolves upon publication of finding."},
  {"id": "s8-9-d-i", "num": "§8.9.d.i", "name": "Draw Challenge", "text": "The named officer or initiating body may challenge a drawn member within 48 hours of NRS publication of the draw on grounds of documented conflict of interest impairing impartiality. JI rules within 48 hours. If sustained, alternate fills the seat. The 21-day review clock is suspended during any pending challenge. No challenge on grounds of State of origin, professional background, or prior pool membership."},
  {"id": "s8-9-e", "num": "§8.9.e", "name": "Ongoing Eligibility", "text": "From acceptance through finding publication, Panel members may not: assume federal elected or appointed position; serve as retained legal counsel in federal proceedings involving the Legislature, either executive, or any Inspectorate; or accept state government executive appointment above department director level. Disqualifying position extinguishes the seat; alternate fills it. Self-recusal permitted at any time."},
  {"id": "s8-9-f", "num": "§8.9.f", "name": "Activation and Meeting Parameters", "text": "Proceeding activated when initiating body transmits grounds to the JI, triggering the draw. The 21-day review clock begins from full Panel constitution — five members accepted and draw challenges resolved. Legislature sets meeting parameters by statute: remote participation, quorum, voting requirements, secure platform. Legislature may not set parameters that prevent effective deliberation or impose undue burden on members. Seven-day window for supplemental documentary submissions; does not extend the 21-day deadline."},
  {"id": "s8-9-g", "num": "§8.9.g", "name": "Scope of Review", "text": "Categorical and bounded review only. Panel determines whether stated grounds constitute at least one enumerated For-Cause removal category. Panel does not investigate, assess credibility, weigh competing facts, evaluate policy merit, or issue orders beyond the binary finding. Finding identifies which categories are present or absent in the submitted record."},
  {"id": "s8-9-h", "num": "§8.9.h", "name": "Effect of Finding", "text": "Substantiated: authorizes Legislature to vote at applicable threshold; triggers duty-suspension. Unsubstantiated: does not bar legislative vote. Both findings published permanently to NRS alongside any subsequent legislative vote. All constitutional voting thresholds remain in effect regardless of finding."},
  {"id": "s8-9-i", "num": "§8.9.i", "name": "SC Review", "text": "Named officer may petition SC within 14 days of NRS publication. Court reviews only Panel's categorical application — not substance or legislative vote. Stay available on showing of probable constitutional error. Court must rule within 21 days. Erroneous determination: proceeding returns to Panel for correction; Legislature may not vote until corrected determination published."},
  {"id": "s8-9-j", "num": "§8.9.j", "name": "Compensation", "text": "No compensation for pool membership. Service-day compensation for each day of active service from acceptance through finding publication. Rates and remote service equivalencies set by statute. State pays; federal government reimburses. Records published to NRS alongside each finding."},
  {"id": "s8-10", "num": "§8.10", "name": "MA Independence Protection", "text": "MA Independence Protection — the Monetary Authority's operational independence is explicitly protected against executive direction. Neither executive may direct, modify, delay, or suppress an MA operational capacity certification. An acting MA Director who issues certifications under executive direction or pressure is subject to the same constitutional accountability framework as a confirmed Director and is constitutionally prohibited from issuing such certifications under political direction."}, {"id": "s8-11", "num": "§8.11", "name": "Eighth-Year Assessment", "text": "The eight-year joint assessment is the constitution's built-in self-evaluation mechanism — the document asking whether it is working as designed. Every eight years, the three Inspectorates jointly assess constitutional performance across all domains: Are rights enforced? Is the Inspectorate reportin"}, {"id": "s9-1", "num": "§9.1", "name": "NRS Properties", "text": "The National Record System — the constitutional backbone of transparency. Permanent, tamper-evident, freely accessible to every Inhabitant at no cost. Every government act required to be published must be on the NRS before it takes legal effect. The NRS is the definitive public record of the Republi"}, {"id": "s9-1-a", "num": "§9.1.a", "name": "Immutability", "text": "NRS Permanence — records published to the NRS may not be deleted, altered, or reclassified after publication. Corrections are published as new entries alongside the original, not as replacements. The full history of any government act — including corrections, amendments, and subsequent interpretatio"}, {"id": "s9-1-b", "num": "§9.1.b", "name": "Distributed Custody", "text": "NRS Access — freely accessible to every Inhabitant at no cost. No registration, no fees, no identification required for read access. The Republic must provide free public access terminals in every State and Territory. The NRS is not a luxury service — it is the mechanism by which Inhabitants verify "}, {"id": "s9-1-c", "num": "§9.1.c", "name": "Public Accessibility", "text": "NRS Publication Requirements — every category of government act required to be published must be published within the time specified by the constitution or enabling statute. Acts not published within their required period are not void (except where the constitution specifically provides otherwise), "}, {"id": "s9-1-d", "num": "§9.1.d", "name": "Cryptographic Signing", "text": "NRS Technical Standards — the Legislature must by statute define the technical standards: format, metadata requirements, search and retrieval standards, and backup and redundancy requirements. The standards must ensure the NRS remains fully functional in the event of a localized technical failure. N"}, {"id": "s9-1-e", "num": "§9.1.e", "name": "Technology Neutrality", "text": "NRS Integrity Audit — the LI audits NRS integrity annually, verifying that: all required publications have been made; no records have been altered or deleted; search and retrieval functions are operating correctly; and access is genuinely free and unrestricted."}, {"id": "s9-1-f", "num": "§9.1.f", "name": "Migration Overlap Protocol", "text": "Third-Party NRS Mirrors — the Legislature may authorize non-governmental organizations to maintain verified mirrors of the NRS for redundancy. Mirrors must meet the same technical standards as the primary NRS. The primary NRS remains a government function — the authorization does not create a privat"}, {"id": "s9-1-g", "num": "§9.1.g", "name": "NRS Self-Authentication", "text": "NRS Classification Exemption for Inspectorate Reports — Inspectorate Reports published to the NRS are permanently exempt from classification, consistent with §8.6.d. The NRS itself may not apply classification restrictions to Inspectorate Reports — the publication platform cannot override the conten"}, {"id": "s9-2", "num": "§9.2", "name": "Historical Records Preservation", "text": "Historical Records Preservation — the NRS includes a permanent historical archive of all prior legislative acts, executive orders, judicial decisions, and government documents dating to the Republic's founding. The Legislature may not delete records from the historical archive — it may annotate them to indicate supersession or repeal, but the original records remain."}, {"id": "s9-3", "num": "§9.3", "name": "Cross-Jurisdictional Record Recognition", "text": "Cross-Jurisdictional Record Recognition — records published to the NRS by one jurisdiction within the Republic are recognized as authentic records by all other jurisdictions without further authentication. The practical foundation for §4.4.b's NRS Authentication provision."},
  {"id": "s9-3-a", "num": "§9.3.a", "name": "RSA Technical Integrity Commission", "text": "A decennial RSA Technical Integrity Commission reviews whether the NRS architecture continues to meet the constitutional requirements for distributed, tamper-evident operation established by §9.1. The Commission has publication authority only — it may not issue binding orders, impose penalties, or direct the RSA Director. Its findings are published jointly by all three Inspectorates to the NRS and cannot be withheld, suppressed, or altered after publication. Qualifications for pool eligibility, "},
  {"id": "s9-3-b", "num": "§9.3.b", "name": "RSA Technical Pool &#x2014; Constitution", "text": "The President and PM each nominate one qualified person per year to the RSA Technical Pool. Each nominee must be confirmed by the Senate within 60 days of nomination by affirmative vote — no deemed-confirmed fallback applies to this position. Senate failure to vote within 60 days is a constitutional compliance failure published to the NRS by the LI. The pool is a public NRS record. Qualifications are defined by statute and certified by the JI at time of nomination. Over a ten-year cycle both exe"},
  {"id": "s9-3-c", "num": "§9.3.c", "name": "Pool Reset", "text": "The RSA Technical Pool resets after each decennial commission cycle. Previously confirmed pool members who did not serve on the commission may be re-nominated by either executive in the new cycle; fresh Senate confirmation under §9.3.b is required and no member carries forward automatically. Members who served on the commission are not eligible for re-nomination to the pool."},
  {"id": "s9-3-d", "num": "§9.3.d", "name": "Commission Draw", "text": "When the decennial review is triggered, all three Inspectorates jointly constitute the Commission by public lottery, drawing five members at random from the eligible pool. The draw is conducted in a public session; all three Inspectorates certify the result and publish it to the NRS before the session closes. The remaining pool members constitute the standing replacement pool for the duration of the Commission's working period."},
  {"id": "s9-3-e", "num": "§9.3.e", "name": "Commission Replacement", "text": "If a Commission member must be replaced during the review period — through ineligibility, withdrawal, or disqualification — all three Inspectorates draw one replacement at random from the remaining eligible pool members using the same public lottery procedure under §9.3.d. The replacement member holds the same authority and obligations as the member they replace."},
  {"id": "s9-3-f", "num": "§9.3.f", "name": "Tri-Inspectorate Oversight", "text": "All three Inspectorates certify the draw under §9.3.d, oversee the Commission's working sessions to verify that the Commission has the access to records, systems, and personnel required by its statutory mandate, and review the Commission's findings before publication to confirm the findings reflect the Commission's genuine conclusions and have not been suppressed or modified. All three Inspectorate seals appear on findings published to the NRS. The RSA Director receives a copy of published findi"},
  {"id": "s9-3-g", "num": "§9.3.g", "name": "Commission Findings", "text": "Commission findings are published directly and jointly to the NRS by all three Inspectorates upon completion of the decennial review. Findings may include assessments of cryptographic integrity, node distribution adequacy, technical standard compliance, and any architectural features that approach or breach constitutional requirements. The Legislature, the RSA Director, and both executives receive findings simultaneously with NRS publication. The Commission's mandate ends upon publication; the C"}, {"id": "s9-4", "num": "§9.4", "name": "NRS and Electoral Integrity", "text": "NRS and Electoral Integrity — all electoral records (voter registration, ballot counts, audit trails, certification documents) must be published to the NRS within the timeframes specified by the Electoral Commission's constitutional mandate under Article XVI. No classification exception applies to electoral records."}, {"id": "s9-5-a", "num": "§9.5.a", "name": "NRS Staffing and Independence", "text": "NRS Staffing and Independence — the NRS is administered by a non-partisan technical office reporting to the LI for oversight. NRS staff may not receive direction from either executive or the Legislature regarding the content, timing, or availability of any record. The NRS administrator is appointed by the LI following public application and qualification review."}, {"id": "s9-5-b", "num": "§9.5.b", "name": "NRS Downtime Protocol", "text": "NRS Downtime Protocol — in the event of a technical outage, government acts that would otherwise have required NRS publication to take effect are delayed until the outage is resolved. Emergency acts required for immediate public safety may be announced through alternative channels, but the NRS publication requirement applies from the moment the NRS is restored."}, {"id": "s9-5-c", "num": "§9.5.c", "name": "Citizen NRS Submissions", "text": "Citizen NRS Submissions — citizens may submit corrections, context, or additional documentation relating to any NRS record via a public submission mechanism maintained by the LI. Submissions are published alongside the original record after accuracy review. Citizens cannot alter government records — only add publicly visible commentary."}, {"id": "s9-5-d", "num": "§9.5.d", "name": "NRS Funding Floor", "text": "NRS Funding Floor — funding for the NRS may not be reduced below the prior year's level without a 2/3 vote of both chambers. The Legislature may increase NRS funding by simple majority. The funding floor protects the NRS from being defunded as a mechanism of opacity — reducing NRS functionality is treated as a constitutional concern."}, {"id": "s9-5-e", "num": "§9.5.e", "name": "Improper Classification", "text": "Classification used to conceal a constitutional violation, an illegal order, or embarrassing but non-sensitive information is constitutionally prohibited in itself. "}, {"id": "s10-1", "num": "§10.1", "name": "The Basic Needs Floor", "text": "The Basic Needs Floor — a constitutional guarantee that the federal government will ensure every Inhabitant has access to a minimum basket of goods and services (food, housing, healthcare, education, and utilities) at a level adequate for a dignified life. Funded by a constitutionally reserved 5% of"}, {"id": "s10-1-a", "num": "§10.1.a", "name": "Anti-Evasion Principle", "text": "BNF Funding Reserve — 5% of gross domestic revenue is constitutionally reserved for the BNF and cannot be redirected. If the BNF requires more than 5%, the Legislature may appropriate additional funding by statute. The reserve is calculated annually by the MA and published to the NRS. During a Sever"}, {"id": "s10-1-d", "num": "§10.1.d", "name": "Severe Contraction Protocol — Activation", "text": "BNF Non-Discrimination — access to BNF benefits may not be conditioned on citizenship, residency status, political affiliation, or any characteristic protected under §1.8. Every Inhabitant receives equal access. The Legislature may not create tiered access based on contribution history or prior bene"}, {"id": "s10-1-e", "num": "§10.1.e", "name": "Severe Contraction Protocol — Effects", "text": "BNF Administration — the PM administers the BNF through the Domestic Affairs Council. Administration must meet the constitutional adequacy standard — delivery mechanisms must actually reach Inhabitants, not merely be nominally available. The LI audits BNF delivery annually."}, {"id": "s10-1-f", "num": "§10.1.f", "name": "Severe Contraction Protocol — Parliamentary Review", "text": "Severe Revenue Contraction — where the MA certifies a severe revenue contraction, the BNF funding floor remains in effect and the National Endowment reserve fund supplements the 5% reserve to ensure BNF continuity. The MA certification triggers automatic activation of the Endowment — no legislative "}, {"id": "s10-1-g", "num": "§10.1.g", "name": "Federal Supplementation Obligation", "text": "BNF and Emergency Declarations — no domestic emergency may reduce, suspend, or otherwise diminish BNF benefits. The BNF is explicitly excluded from emergency powers. A PM who attempts to redirect BNF funds during an emergency has committed a constitutional breach reportable by the EI."}, {"id": "s10-2", "num": "§10.2", "name": "Fiscal Accountability Framework", "text": "Fiscal Accountability — the constitutional framework for government spending discipline. The Legislature must pass a balanced budget or publish a structural deficit justification. The fiscal framework is enforced by the Inspectorates — the LI audits legislative fiscal claims, the EI audits executive spending certifications."}, {"id": "s10-2-a", "num": "§10.2.a", "name": "Tax Origination and Fiscal Objection", "text": "Deficit Threshold — structural deficits above the constitutional threshold (defined by the MA by statute) require a published justification from the Legislature and a published plan for return to balance. The MA reviews the justification for fiscal accuracy — not political adequacy."}, {"id": "s10-2-b", "num": "§10.2.b", "name": "Annual Budget and Continuation Spending", "text": "National Endowment — the Legislature must by statute establish a National Endowment reserve fund for BNF backstop purposes during severe revenue contractions. Funded by appropriation in years of fiscal surplus. If the Legislature fails to establish the Endowment within the constitutionally required "}, {"id": "s10-3", "num": "§10.3", "name": "Public Campaign Financing", "text": "Public Campaign Financing — the Legislature must by statute establish a public campaign financing system by the constitutional deadline. If it fails to do so, the failure triggers automatic referendum eligibility under §11.1 — citizens may petition for a national vote on whether to impose a public financing framework by citizen mandate."}, {"id": "s10-3-a", "num": "§10.3.a", "name": "Campaign Financing Standards", "text": "Campaign Financing Standards — the public financing system must provide all registered candidates with equal access to public funds. No incumbent advantage in the allocation formula. Private contributions are capped at the de minimis threshold under §18.3. Administered by the Electoral Commission — not by either executive or the Legislature."}, {"id": "s10-3-b", "num": "§10.3.b", "name": "BNF and Contraction Exemptions", "text": "Enforcement of Campaign Financing — violations are a constitutional breach reportable by the EI. The EI audits all campaign finance records within 90 days of any election. Candidates who received impermissible contributions must refund them or have the amount treated as an undisclosed in-kind contri"}, {"id": "s10-4-a", "num": "§10.4.a", "name": "MA Director — Elected Office", "text": "MA Director Election and Board Composition — the MA is governed by an elected Director and a board of five appointed members. The Director is elected by national RCV on National Election Day to a single non-renewable 8-year term, staggered from the board member appointment cycle. The elected Director gives the MA democratic legitimacy while the single non-renewable term protects independence — the Director cannot be captured by political interests whose support would secure re-election."}, {"id": "s10-4-b", "num": "§10.4.b", "name": "MA Independence", "text": "MA Independence and Mandate — the MA's hierarchical mandate is constitutionally fixed: primary mandate is price stability and fiscal solvency; secondary mandate is regard for employment conditions and sustainable growth. The primary mandate takes precedence in all cases of conflict. This hierarchy c"}, {"id": "s10-4-c", "num": "§10.4.c", "name": "Transparency", "text": "MA Transparency — all MA determinations, rate decisions, board votes, dissents, and mandate analyses must be published to the NRS within 48 hours of the board meeting. Board Member dissents are published alongside the majority determination. The transparency requirement serves as both an accountabil"}, {"id": "s10-4-d", "num": "§10.4.d", "name": "Methodology Integrity", "text": "MA Methodology Integrity — the MA's calculation methodologies must be published and publicly available. The MA may not change its published methodology without 90 days' notice and a published explanation. Covert methodology changes — changing how the numbers are calculated without telling anyone — a"}, {"id": "s10-4-e", "num": "§10.4.e", "name": "Uncertifiable Inherited Fiscal Position", "text": "Uncertifiable Inherited Fiscal Position — where the MA cannot certify the incoming government's fiscal position because the inherited data is too incomplete or unreliable, the MA publishes a qualified certification explaining the limitations. The Legislature must respond within 30 days with a plan t"},
  {"id": "s10-4-f", "num": "§10.4.f", "name": "Director-Board Authority", "text": "The MA Director chairs the board and holds veto authority over board decisions. The board of five members decides by majority vote; the Director does not hold a board vote. The Director may veto any board decision by publishing written grounds to the NRS within the period the Legislature defines by statute; a veto without published grounds is constitutionally void. The board may override a Director veto by 4-of-5 supermajority; the override and its grounds are published to the NRS. Where a board"}, {"id": "s10-5-a", "num": "§10.5.a", "name": "Official Benefits", "text": "Personal Financial Disclosure — all elected and appointed constitutional officers must disclose all financial interests, holdings, income sources, and liabilities to the EI within 30 days of taking office and annually thereafter. Disclosure records are published to the NRS."}, {"id": "s10-5-b", "num": "§10.5.b", "name": "Financial Disclosure", "text": "Conflict of Interest Recusal — any constitutional officer with a direct financial interest in a decision within their authority must recuse themselves from that decision. Recusal is self-executing — the officer cannot be excused from recusal by the PM, President, or Legislature. Failure to recuse wh"}, {"id": "s10-5-c", "num": "§10.5.c", "name": "Integrity Bans", "text": "Post-Service Restrictions — constitutional officers may not, for 5 years after leaving office, engage in activities that monetize non-public information acquired during service. The restriction covers lobbying, consulting, and any advisory role that draws on confidential government knowledge."}, {"id": "s10-5-d", "num": "§10.5.d", "name": "Anti-Ego Provision", "text": "Gift and Hospitality Rules — constitutional officers may not accept gifts or hospitality above a de minimis threshold defined by statute. All gifts above the threshold must be disclosed to the EI within 30 days and deposited with the relevant treasury. Retention without disclosure is a constitutiona"}, {"id": "s10-5-e", "num": "§10.5.e", "name": "Official Records Belong to the Republic", "text": "Official Records Retention — all records created in the exercise of official functions are public records. Constitutional officers may not retain, destroy, or remove official records after leaving office. Records physically retained without authorization are subject to forfeiture."}, {"id": "s10-5-f", "num": "§10.5.f", "name": "Official Gifts", "text": "Revolving Door Restriction — constitutional officers may not move directly from government service into private roles that would allow them to exploit relationships, knowledge, or access accumulated during service. The 5-year cooling-off period applies to regulated industries directly affected by th"}, {"id": "s10-5-g", "num": "§10.5.g", "name": "Official Intellectual Property", "text": "Official Intellectual Property — ideas, analyses, and work product created during official service belong to the Republic. An officer may not monetize work done in their official capacity for 5 years following service. For classified information, the 5-year cooling-off applies after declassification"}, {"id": "s10-5-h", "num": "§10.5.h", "name": "Oath of Office Requirement", "text": "Ethics Enforcement — the EI is the primary enforcement mechanism for the §10.5 ethics provisions. The EI publishes all disclosed conflicts, all flagged violations, and all referrals to the Legislature for removal proceedings. The EI publishes facts and refers serious violations — it does not impose "}, {"id": "s10-6-a", "num": "§10.6.a", "name": "National Endowment Governance", "text": "National Endowment Governance — governed by a board of trustees appointed by the PM from JI-maintained candidates, confirmed by the Senate. The board's sole mandate is to preserve and grow the Endowment fund for BNF backstop purposes — it may not be directed to other investment goals by either executive or the Legislature."}, {"id": "s10-6-b", "num": "§10.6.b", "name": "Defense Readiness and Veterans Obligations", "text": "Endowment Activation — when the MA certifies a Severe Revenue Contraction under §10.1.f, the Endowment is automatically activated. The board must begin BNF supplement disbursements within 30 days. Disbursements continue until the MA certifies that the revenue contraction has ended. The board may not"}, {"id": "s11-1", "num": "§11.1", "name": "Optional Referendum", "text": "Optional Referendum — citizens may initiate a national referendum to repeal enacted legislation by petition of 5% of eligible voters within 90 days of enactment. The JI screens petitions for eligibility — laws that solely or primarily expand an Article I right are not eligible for referendum (the Bi"}, {"id": "s11-1-a", "num": "§11.1.a", "name": "Citizen Petition Right", "text": "Petition Requirements — the 5% petition must be collected within 90 days of the law's enactment. The EI verifies petition signatures for eligibility. If the threshold is met, the EC administers the referendum within 90 days of verification. Petitioners may withdraw the petition before the referendum"}, {"id": "s11-1-b", "num": "§11.1.b", "name": "Eligibility Screen", "text": "JI Eligibility Screening — the JI determines whether a targeted law is eligible for referendum. Laws that solely or primarily expand an Article I right are ineligible — the Individual Sovereignty Floor can expand but cannot contract through popular vote. The JI's eligibility determination is final s"}, {"id": "s11-1-c", "num": "§11.1.c", "name": "Referendum Thresholds and Finality", "text": "Referendum Outcome — if the referendum passes (simple majority of votes cast, subject to the Legislature-defined turnout threshold), the law is repealed immediately upon EC certification. If it fails, the law remains in effect and cannot be subjected to referendum on the same grounds for 5 years. Th"}, {"id": "s11-2-a", "num": "§11.2.a", "name": "Subsidiarity Principle", "text": "Citizen Legislative Initiative — distinct from the referendum, the initiative allows citizens to propose legislation directly. 10% of eligible voters petition for a specific legislative proposal. The Legislature must vote on the proposal within 90 days. If it fails or is not voted on, the proposal p"}, {"id": "s11-2-b", "num": "§11.2.b", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as the primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their constitutional functions. States may not starve local"}, {"id": "s12-1", "num": "§12.1", "name": "Authorized Purposes for Military Force", "text": "Authorized Purposes for Military Force — the constitution limits military force to three purposes: border protection and territorial integrity; defense of treaty allies within defined triggering thresholds; and prevention of genocide or civilizational collapse. Three prohibited purposes are equally "}, {"id": "s12-2", "num": "§12.2", "name": "Legislative Declaration of Defense", "text": "Emergency Defense Allocation — the automatic funding mechanism that activates with a Tier 3 Declaration. The PM certifies funds concurrent with the Legislative Declaration — no Declaration takes effect without PM certification. The allocation covers specific categories of military expenditure define"}, {"id": "s12-2-a", "num": "§12.2.a", "name": "Legislative Declaration of Defense", "text": "Allocation Categories — the Declaration must specify which expenditure categories are authorized: operational costs, equipment, personnel, intelligence support, logistics, and post-conflict obligations. Expenditure in uncategorized areas requires a supplementary PM certification. The categorization "}, {"id": "s12-2-b", "num": "§12.2.b", "name": "Five-Year Maximum", "text": "Allocation Renewal — the Emergency Defense Allocation renews automatically with each 180-day Declaration renewal, subject to PM certification. If the Legislature renews the Declaration but the PM withholds certification, the Declaration is voided — the PM's fiscal certification is an independent con"}, {"id": "s12-2-c", "num": "§12.2.c", "name": "Successive Declaration Standard", "text": "Allocation Termination — when the Tier 3 Declaration expires or is not renewed, all Emergency Defense Allocation expenditure ceases automatically within 48 hours. Ongoing contracts within the certified allocation may continue to wind down for 30 days. New commitments may not be entered after Declara"}, {"id": "s12-2-d", "num": "§12.2.d", "name": "Senate Armed Services Committee", "text": "Oversight of Allocation — the EI audits Emergency Defense Allocation spending quarterly during any active Tier 3 Declaration and publishes findings to the NRS. The audit covers whether expenditure falls within certified categories, whether PM certifications were obtained, and whether expenditure com"}, {"id": "s12-2-e", "num": "§12.2.e", "name": "Military Authority During Presidential Succession Vacuum", "text": "Post-Allocation Accountability — within 180 days of a Declaration's final expiry, the EI publishes a comprehensive allocation accountability report covering the entire period: total expenditure by category, compliance with PM certifications, and any identified irregularities."}, {"id": "s12-3", "num": "§12.3", "name": "Intelligence Firewall", "text": "Defense Intelligence — the use of intelligence capabilities in support of authorized military operations. The §1.29.d Intelligence Firewall applies at all times — no military operation authorizes domestic intelligence collection against citizens. Intelligence activities must be published to the NRS "}, {"id": "s12-4", "num": "§12.4", "name": "Military Accountability", "text": "Post-Conflict Obligations — before any extended military engagement concludes, the Senate must approve a Transition and Reconstruction Plan specifying the Republic's post-conflict obligations: status of alliance obligations, civilian reconstruction support, transitional justice support, and withdraw"}, {"id": "s12-5-a", "num": "§12.5.a", "name": "Treaty Emergency Certification", "text": "Treaty Emergency Certification — where an existing treaty requires emergency military action, the President may invoke Treaty Emergency Certification as an alternative to the standard Tier authorization process. The certification must be published to the NRS within 6 hours with the specific treaty o"}, {"id": "s12-5-c", "num": "§12.5.c", "name": "No Blank Check", "text": "The Treaty Emergency Certification covers operational costs for the initial response and triggers parliamentary authorization for any extended engagement. Treaties "}, {"id": "s13-1", "num": "§13.1", "name": "Territorial Compact", "text": "Territorial Status — the foundational category for non-State jurisdictions within the Republic. A Territory operates under a Territorial Compact, has federal protections under Article I, receives BNF benefits, and may begin the Statehood pathway under §13.2. Territories are represented in the House "}, {"id": "s13-2", "num": "§13.2", "name": "The Statehood Audit", "text": "Requirements for Statehood — the pathway from Territory to State is automatic upon successfully completing the Statehood Audit and Provisional Membership Period. No political vote in Congress is required once the audit is passed — statehood is a constitutional entitlement for any Territory that meet"}, {"id": "s13-2-a", "num": "§13.2.a", "name": "Fiscal Integrity", "text": "Statehood Audit — Fiscal Integrity Criterion. The LI audits the territory's government finances for basic fiscal sustainability, absence of structural insolvency that would require federal bailout, and basic public financial management standards. The audit checks whether the territory can function a"}, {"id": "s13-2-b", "num": "§13.2.b", "name": "Legal Sync", "text": "Statehood Audit — Article I Legal Compliance Criterion. The JI audits the territory's legal system for compliance with every Article I right. Statehood is not granted to jurisdictions that are constitutionally non-compliant — a territory that applies Article I rights inconsistently cannot become a S"}, {"id": "s13-2-c", "num": "§13.2.c", "name": "The Provisional Membership Period", "text": "Provisional Membership Period — upon passing the Statehood Audit, the territory enters a Provisional Membership Period of between 365 and 900 days (Legislature defines by statute). Clean completion results in automatic Statehood — no further action required."}, {"id": "s13-2-d", "num": "§13.2.d", "name": "Partial Territory Statehood", "text": "Partial Territory Statehood — a defined geographic subdivision of a Territory may petition for Statehood independently of the remainder. The petitioning subdivision must meet the same Statehood criteria as a whole Territory. Used where a Territory contains a region with clearly different institution"}, {"id": "s13-2-e", "num": "§13.2.e", "name": "Minimum Democratic Legitimacy", "text": "Minimum Democratic Legitimacy — every State must maintain three ongoing conditions: functioning electoral processes under Article XVI, basic rule of law and judicial function, and Article I rights compliance. Annual Statehood Audit verifies continued compliance. A State that fails receives Early War"}, {"id": "s13-2-f", "num": "§13.2.f", "name": "Territorial Minimum Institutional Floor", "text": "Territorial Minimum Institutional Floor — every Territory must maintain basic governance infrastructure: a governance council with defined membership and published authority, basic public financial reporting, and access to federal court jurisdiction for Article I claims. Territories that cannot main"}, {"id": "s13-2-g", "num": "§13.2.g", "name": "Conflict-Affected State Provisional Status", "text": "Conflict-Affected State Provisional Status — where active conflict prevents completion of the annual Statehood Audit in a significant portion (>25% population) of a State's territory, the LI may grant provisional status for that audit cycle. Preserves State constitutional standing and BNF protection"}, {"id": "s13-3", "num": "§13.3", "name": "Mandatory Devolution", "text": "Mandatory State Devolution — the remedial process for States that have failed to meet minimum governance standards over a sustained period. Not punishment — a constitutional alternative to indefinite dysfunction. The path back to full Statehood is always available. Devolution restructures the State'"}, {"id": "s13-3-a", "num": "§13.3.a", "name": "Devolution Triggers", "text": "Devolution Triggers — a State enters Mandatory Devolution if it fails three consecutive annual Statehood Audits after passing through the Early Warning (Year 1-2) and Devolution Vote (Year 3) stages without correction. The LI certifies the trigger; the EI and JI jointly confirm; the SC reviews the f"}, {"id": "s13-3-b", "num": "§13.3.b", "name": "Early Warning — Years 1 and 2", "text": "Early Warning — Year 1 and 2 audit failures trigger Early Warning: the LI publishes specific compliance requirements, the State submits a Remediation Plan within 60 days, and the LI monitors implementation quarterly. A cooperative remediation process — the federal government assists the State in cor"}, {"id": "s13-3-c", "num": "§13.3.c", "name": "Devolution Vote — Year 3", "text": "Devolution Vote — Year 3 failure triggers a State-level referendum: citizens vote on whether to proceed to devolution or accept a federal remediation commission. If the State chooses the remediation commission, devolution is suspended for 2 years. If devolution is chosen or the commission fails, §13"}, {"id": "s13-3-d", "num": "§13.3.d", "name": "Effect of Mandatory Devolution", "text": "Effect of Mandatory Devolution — the devolving State's territory is restructured: subdivided, merged with adjacent States or Territories, or maintained as a Territory under federal administration pending re-qualification. Citizens retain all Article I rights throughout. BNF benefits continue without"}, {"id": "s13-3-e", "num": "§13.3.e", "name": "Constitutional Challenge to Devolution", "text": "Re-Qualification Pathway — a devolving jurisdiction may re-qualify for Statehood by completing the full Statehood process under §13.2 from territorial status. No minimum waiting period before beginning re-qualification. The process is the same as the initial Statehood process — the jurisdiction must"}, {"id": "s13-4", "num": "§13.4", "name": "Voluntary Devolution", "text": "Voluntary State Devolution — a State may voluntarily seek to restructure its relationship with the Republic. Requires a State referendum (60% of voters), a negotiated restructuring agreement approved by the Senate, and a Transition Plan published to the NRS. The voluntary path preserves far more Sta"}, {"id": "s13-4-a", "num": "§13.4.a", "name": "Voluntary Devolution Vote", "text": "Voluntary Devolution Referendum — 60% of State voters must approve the voluntary devolution petition. The referendum must specify the proposed restructuring: subdivision, merger, conversion to Territory status, or other arrangement. Citizens vote on the specific proposal, not on abstract devolution."}, {"id": "s13-4-b", "num": "§13.4.b", "name": "Fiscal Transparency Requirement", "text": "Negotiated Restructuring Agreement — following a successful referendum, the State and the federal government negotiate restructuring terms: asset and liability allocation, transition timeline, continuing federal obligations, and constitutional status of successor jurisdictions. Senate approval by 2/"}, {"id": "s13-4-c", "num": "§13.4.c", "name": "Net-Contributor Transparency", "text": "Transition Plan — specifies which functions transfer and when, how citizen rights are maintained during transition, and what happens if transition encounters implementation problems. The LI monitors Transition Plan implementation and publishes quarterly compliance reports."}, {"id": "s13-4-d", "num": "§13.4.d", "name": "Effect of Voluntary Devolution", "text": "Post-Devolution Status — following voluntary devolution, successor jurisdiction(s) begin their constitutional status from the starting point specified in the restructuring agreement. A subdivision that becomes a Territory enters the Statehood pathway immediately."}, {"id": "s13-4-e", "num": "§13.4.e", "name": "Negotiated Devolution Pathway", "text": "Voluntary Devolution and BNF — during any voluntary devolution process, BNF benefits continue without interruption. The Transition Plan must specify how BNF delivery continues during the transition. BNF continuity is non-negotiable in the restructuring agreement."}, {"id": "s13-6", "num": "§13.6", "name": "Voluntary Incorporation", "text": "A devolved State loses its Senate seats on the date the Devolution Motion passes. It retains House seats proportional to population. Federal law continues to apply. The State government continues as territorial administration under federal oversight. All effects are published to the NRS the moment t"}, {"id": "s14-1", "num": "§14.1", "name": "Acknowledgment of Prior Sovereignty", "text": "Indigenous Nation Compact — the foundational provision recognizing that Indigenous Nations within the Republic's territory hold a distinct constitutional relationship based on prior sovereignty. The compact relationship is bilateral: the Republic acknowledges Indigenous prior sovereignty; Indigenous"}, {"id": "s14-2", "num": "§14.2", "name": "Compact Formation", "text": "Compact Formation — an Indigenous Nation may enter a compact with the Republic by submitting a compact proposal to the Senate. The Senate must respond within 90 days. Compact terms are negotiated between the Nation and the PM's domestic affairs office, with JI oversight. Compacts take effect upon 2/3 Senate ratification and Indigenous Nation ratification by their own constitutional process."}, {"id": "s14-3-a", "num": "§14.3.a", "name": "Article I Rights in Compact Territories", "text": "Article I Rights in Compact Territories — Article I rights apply in full within compact territories. No compact provision may limit or qualify any Article I right. The compact creates a framework for Indigenous governance, not a carve-out from constitutional rights. Where compact governance conflicts with an Article I right, Article I prevails."}, {"id": "s14-3-b", "num": "§14.3.b", "name": "Compact Judicial Authority", "text": "Compact Judicial Authority — Indigenous Nations with compacts may establish their own courts with jurisdiction over matters within compact scope. These courts operate in parallel with federal courts. Citizens may bring Article I claims directly to federal courts regardless of whether a matter is within compact scope."}, {"id": "s14-3-c", "num": "§14.3.c", "name": "Land and Resource Sovereignty", "text": "Land and Resource Sovereignty — compact territories include explicit land and resource sovereignty provisions negotiated between the Nation and the Republic. The Republic may not alter compact land provisions without Nation consent. Resource extraction within compact territories requires both Republic and Nation approval."}, {"id": "s14-3-d", "num": "§14.3.d", "name": "Compact Governance Recognition", "text": "Compact Governance Recognition — the Republic recognizes the Indigenous Nation's governance structures as legitimate political institutions within compact scope. Federal agencies must coordinate with compact governance bodies. The Republic may not impose federal administrative structures on compact governance without Nation consent."}, {"id": "s14-3-e", "num": "§14.3.e", "name": "Compact Education and Language", "text": "Compact Education and Language — compacts must include provisions for preservation and transmission of Indigenous languages and cultural practices. The Republic provides federal education funding that supports Indigenous-language instruction within compact territories."}, {"id": "s14-4-a", "num": "§14.4.a", "name": "Compact Dispute Resolution", "text": "Compact Dispute Resolution — disputes about compact terms are resolved through a Joint Compact Review Council (equal representation of the Nation and the Republic) with appeal to the SC on constitutional questions. The Council's decisions are binding on both parties within the scope of the compact. Neither party may unilaterally declare a compact dispute resolved."}, {"id": "s14-4-b", "num": "§14.4.b", "name": "Compact Review Cycle", "text": "Compact Review Cycle — compacts are reviewed on a schedule defined in the compact terms, minimum every 20 years. Either party may request a review outside the scheduled cycle. Reviews are conducted by the Joint Compact Review Council. The review may result in compact amendment by mutual agreement — neither party can impose amendments."}, {"id": "s14-4-c", "num": "§14.4.c", "name": "Compact Termination", "text": "Compact Termination — a compact may be terminated by mutual agreement only. Neither party may unilaterally terminate a compact. If the Nation seeks termination, the Republic must negotiate exit terms within 2 years. If no agreement is reached, the compact continues and the dispute is referred to the SC."}, {"id": "s14-5-a", "num": "§14.5.a", "name": "Emergency Rights Writ", "text": "Emergency Rights Writ — any resident of compact territory who believes an Article I right has been violated may bring an Emergency Rights Writ directly to the SC, bypassing all lower courts and the compact dispute resolution process. The SC must respond within 7 days. Cannot be displaced by compact terms — a direct constitutional remedy that exists independently of compact jurisdiction."}, {"id": "s14-5-b", "num": "§14.5.b", "name": "Federal Assistance Obligations", "text": "Federal Assistance Obligations — the Republic maintains specific assistance obligations to compact nations: federal education funding, healthcare access, infrastructure investment, and emergency response. These obligations are enforceable against the Republic by the Nation through the compact dispute resolution process."}, {"id": "s14-5-c", "num": "§14.5.c", "name": "New Indigenous Compact Petitions", "text": "New Indigenous Compact Petitions — Indigenous communities that do not currently hold a compact may petition the Senate for compact recognition. The Senate must consider the petition within 90 days and either begin compact negotiations or publish written reasons for declining. A declined petition may be re-submitted after 5 years or after a material change in circumstances."}, {"id": "s14-5-d", "num": "§14.5.d", "name": "Compact and Citizenship", "text": "Compact and Citizenship — Indigenous Nation membership and Republic citizenship are compatible and independent statuses. A citizen of a compact Nation holds full Republic citizenship rights. Republic citizenship does not require renouncing Indigenous Nation membership. Dual status is the constitutional default."}, {"id": "s14-6", "num": "§14.6", "name": "Treaty Supremacy and Continuity", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded through the FPIC framework."}, {"id": "s15-1", "num": "§15.1", "name": "Three Amendment Paths", "text": "The Three Amendment Paths — the constitution can be amended through three routes with varying levels of democratic mandate. Path A (Legislature only): 3/4 of both chambers simultaneously. Path B (Legislature + popular vote): 2/3 of both chambers + 55% affirmative with 55% participation. Path C (citizens alone): 70% affirmative with 65% participation. An amendment passed by any path has identical constitutional force."}, {"id": "s15-1-a", "num": "§15.1.a", "name": "Parliamentary Path", "text": "Path A — Legislative Amendment. Requires 3/4 supermajority of the full seated membership of both chambers in a single concurrent vote. No popular referendum. No executive signature. Every member's vote is published to the NRS within 24 hours. The 3/4 threshold is the highest legislative supermajorit"}, {"id": "s15-1-b", "num": "§15.1.b", "name": "Parliamentary and Popular Path", "text": "Path B — Legislative and Popular Amendment. Lower legislative threshold (2/3 both chambers) but requires the People to ratify. National popular vote within 180 days of the parliamentary vote. 55% affirmative support with at least 55% citizen participation required. EC and LI certify jointly. Neither"}, {"id": "s15-1-c", "num": "§15.1.c", "name": "Citizen-Led Path", "text": "Path C — Citizen-Led Amendment. The only path that entirely bypasses the Legislature. 70% affirmative support with 65% citizen participation required. A vote that fails either threshold fails; no second vote is available. A new petition may be filed immediately under the same process, with the failed vote's NRS record available as public evidence of prior support."}, {"id": "s15-2", "num": "§15.2", "name": "No Executive Veto Over Amendments", "text": "No Executive Veto of Amendments — neither the President nor the PM has any role in the constitutional amendment process. No signature required. No veto available. An amendment takes effect the moment the Inspectorates certify ratification and publish it to the NRS. Constitutional change is entirely "}, {"id": "s15-2-a", "num": "§15.2.a", "name": "No Executive Veto", "text": "Amendment Takes Effect — an amendment takes effect immediately upon LI certification (Paths A and B) or EC certification (Path C) and NRS publication. No implementation delay, no commencement date, no executive discretion over timing."}, {"id": "s15-3-a", "num": "§15.3.a", "name": "Permanently Unamendable Provisions", "text": "The Unamendable Floor — six provisions that cannot be amended by any process: §1.2 (torture prohibition), §1.3 (slavery and forced labor), §1.13 (habeas corpus), §1.17 (public trial), §1.18 (no retroactive criminal laws), §1.27 (non-refoulement). Article I as a whole can only expand — no amendment m"}, {"id": "s15-4-a", "num": "§15.4.a", "name": "Territorial Integrity", "text": "Territorial Integrity — the Republic's territorial extent may only be reduced by a Path B or Path C amendment (not Path A). Expansion of territory is governed by §13.1. No executive action may alter the Republic's territorial extent."}, {"id": "s15-4-b", "num": "§15.4.b", "name": "Advisory Referenda", "text": "No Secession by Ordinary Legislation — a State may not secede from the Republic by ordinary statute or by State referendum alone. Secession requires a constitutional amendment — Path B or C — meaning a national democratic majority must consent to the departure of any State."}, {"id": "s15-5", "num": "§15.5", "name": "Independence Transition Framework", "text": "Amendment Consistency Requirement — an amendment that is logically inconsistent with an existing provision must either explicitly repeal the inconsistent provision or the inconsistency is treated as void. The LI reviews all proposed amendments for internal consistency before ratification."}, {"id": "s15-5-a", "num": "§15.5.a", "name": "Framework Agreement Requirement", "text": "LI Consistency Review — the LI publishes a consistency analysis of any proposed amendment within 30 days of its official proposal. Identifies provisions the amendment would supersede, modify, or conflict with. Advisory — it does not block ratification — but creates a permanent public record of what "}, {"id": "s15-5-b", "num": "§15.5.b", "name": "Transition Period — 24 to 60 Months", "text": "SC Consistency Adjudication — if a ratified amendment's consistency with existing provisions is disputed, the SC resolves the dispute on expedited review. The SC may not refuse to ratify an amendment that has met its procedural thresholds — it adjudicates the consistency question after ratification,"}, {"id": "s15-5-c", "num": "§15.5.c", "name": "Basic Needs Floor Transition", "text": "Retroactive Effect of Amendments — amendments take prospective effect from the date of ratification. They do not retroactively alter the constitutionality of acts that were constitutional when performed. Criminal prosecutions and civil proceedings that were constitutionally valid when commenced rema"}, {"id": "s15-5-d", "num": "§15.5.d", "name": "Executive Authority During Transition", "text": "Simultaneous Amendments — two amendments may be simultaneously in the ratification process. If both pass, both are law. If they conflict with each other, the one ratified later in time prevails. Where two conflicting amendments are certified on the same day, the amendment with the higher ratification margin prevails; where margins are also equal, the amendment whose proposal stage was completed earlier in time prevails as determined by the LI from NRS records. The LI publishes a notice of any pe"}, {"id": "s15-5-e", "num": "§15.5.e", "name": "Simultaneous Independence Sequencing", "text": "Withdrawn Amendments — a proposed amendment may be withdrawn by the proposing body at any point before ratification is certified. Once ratification is certified, an amendment may only be reversed by a subsequent amendment through one of the three paths."}, {"id": "s15-6", "num": "§15.6", "name": "Supremacy of This Constitution", "text": "Constitutional Supremacy — this Constitution is the supreme law of the Federated Republic. All legislative acts, executive orders, treaties, administrative decisions, and government actions must be consistent with this Constitution. Any provision inconsistent with this Constitution is void to the ex"}, {"id": "s15-6-b", "num": "§15.6.b", "name": "Federal-State Statutory Hierarchy", "text": "Despite §10.1 applying to Republic Inhabitants, the Republic's obligations to the departing territory during the transition period must be specified in the framework agreement. Independence does not end Republic obligations to former Territory residents immediately. The transition period is a period"}, {"id": "s16-2", "num": "§16.2", "name": "Electoral Commission Qualifications", "text": "Electoral Commission members must meet three independently verified requirements: at least 15 years of professional expertise in elections, technology, or public administration; no current or recent partisan affiliation; and passage of the Constitutional Logic Test. The qualifications are substantiv"}, {"id": "s16-2-a", "num": "§16.2.a", "name": "Electoral Commission Removal", "text": "For-cause only — no no-cause removal. EC administers all elections; no-cause removal would be a vector for electoral manipulation. Process: JI documents finding → State Designee Panel substantiates → 14-day SC appeal window expires (or SC upholds on appeal) → member suspended from all EC duties. The"}, {"id": "s16-3", "num": "§16.3", "name": "NVS Properties", "text": "Three constitutionally required properties of the National Voting System: ballot secrecy (technically impossible to link any vote to any voter), public auditability (aggregate results mathematically verifiable by anyone with NRS access), and resilience (capable of operating in degraded conditions wi"}, {"id": "s16-3-a", "num": "§16.3.a", "name": "Ballot Secrecy", "text": "No person or institution — including Electoral Commission members — may identify how any individual citizen voted. Ballot secrecy is constitutionally absolute. The NVS must make it technically impossible to link any vote to any voter, even in post-election audits."}, {"id": "s16-3-b", "num": "§16.3.b", "name": "Public Auditability", "text": "Every vote cast through the NVS must be individually verifiable by the voter who cast it, without revealing that voter's identity to any other party. The NVS must produce an audit trail that allows independent verification of aggregate results without individual identification. Both requirements mus"}, {"id": "s16-3-c", "num": "§16.3.c", "name": "Resilience and Privacy", "text": "The NVS must operate in degraded conditions without compromising ballot secrecy or auditability. No information generated by the NVS — including voter participation records — may be shared with any government body, law enforcement, or foreign entity for any purpose other than administering the relev"}, {"id": "s16-4-a", "num": "§16.4.a", "name": "The Citizen Voting Credential", "text": "The Citizen Voting Credential is issued and managed by the Electoral Commission. The system stores only cryptographic identifiers — not names, biometric data, or personal information — ensuring the link between a citizen and their credential cannot be used to..."}, {"id": "s16-4-b", "num": "§16.4.b", "name": "Remote Voting", "text": "Legislature may by statute authorize authenticated remote voting through the NVS. Remote voting must meet the same cryptographic and auditability standards as in-person NVS voting. No remote voting system may reduce ballot secrecy or auditability below the in-person standard."}, {"id": "s16-4-c", "num": "§16.4.c", "name": "State Voting Method Flexibility", "text": "States may implement early voting periods, mail-in ballot options, and alternative participation methods, provided all methods connect to the NVS and meet its cryptographic and auditability standards. States may not reduce NVS access or capacity as a condition of offering alternative methods. Added "}, {"id": "s16-4-d", "num": "§16.4.d", "name": "Federal Ballot Information", "text": "Before each federal election window opens, the Electoral Commission delivers to every eligible citizen: the list of federal races on their ballot, the NVS access procedures, and the certification timeline. Delivery must reach every eligible citizen through at least two distinct channels. Added v143."}, {"id": "s16-4-e", "num": "§16.4.e", "name": "State Ballot Information on Request", "text": "At a state's request, EC may extend ballot information delivery to cover state and local races. State bears cost. EC cannot refuse except on operational capacity grounds. Entirely voluntary. New in v143."}, {"id": "s16-5-a", "num": "§16.5.a", "name": "Campaign Funding", "text": "Campaigns for Electoral Commission seats are publicly funded in full. No private money may be spent on EC campaigns. The EC administers elections for all other offices — it cannot itself be captured by the interests that it would regulate in other campaigns."}, {"id": "s16-5-b", "num": "§16.5.b", "name": "JI Oversight", "text": "The Judicial Inspectorate audits the Electoral Commission annually. The JI is the appropriate Inspectorate for EC oversight — it audits judicial independence, and electoral integrity has similar structural properties. JI audit findings on the EC are published to the NRS and presented to both chamber"}, {"id": "s16-5-c", "num": "§16.5.c", "name": "Removal", "text": "For-cause only, 2/3 both chambers simultaneously, preceded by State Designee Panel verification. 180-day election proximity rule: any removal vote within 180 days of a major national election is automatically suspended pending SC review within 48 hours. Critically: the proximity restriction applies "}, {"id": "s16-5-d", "num": "§16.5.d", "name": "Mid-Term Vacancy", "text": "Where any Electoral Commission seat becomes vacant mid-term, a special election is held within 90 days through the NVS. The replacement serves the remainder of the vacated seat's term, then may stand as a candidate at the next regular EC election for a full new non-renewable term. Where fewer than 18 months remain in the vacated seat's term, the replacement may stand for a full term at the next regular EC election without serving the remainder. The Commission operates under its active-membership"},
  {"id": "s16-1", "num": "§16.1", "name": "Electoral Commission", "text": "The Electoral Commission is a constitutionally independent body of five members elected by national ranked-choice vote on National Election Day to non-renewable six-year staggered terms. No political body nominates EC members. The EC administers all federal elections and referenda, maintains the National Voting System, enforces Article XVIII campaign finance requirements, and certifies all election results to the NRS. The EC is independent of both executives and the Legislature in the exercise o"}, {"id": "s16-6", "num": "§16.6", "name": "Electoral Commission Technical Deadlock", "text": "Legislature must establish by statute a procedure for the EC to adopt temporary technical measures in imminent security threats or system failures, bypassing the normal 3/5 decision threshold. The emergency power is narrowly constrained — it cannot change electoral rules, timelines, or candidate eli"}, {"id": "s16-7", "num": "§16.7", "name": "Day Zero Voting System Transition", "text": "Legislature must establish by statute the transition from any predecessor voting infrastructure to the constitutionally required NVS. The statute must ensure continuity of democratic participation — no gap between the predecessor system going offline and the NVS coming online. The ratification vote "}, {"id": "s17-1", "num": "§17.1", "name": "The Use Doctrine", "text": "Federal government holds no territorial sovereignty within any State or Territory. All federal property rights are functional use rights — operational control over a designated footprint for the duration of the stated function. Use rights do not constitute ownership, do not transfer sovereignty from"}, {"id": "s17-2", "num": "§17.2", "name": "Seat of Government", "text": "The Republic holds no territorial sovereignty at its Seat of Government. The Seat is hosted by a State or Territory selected through the competitive bid process under this Article. The federal government holds only Operational Use Rights (§17.3) over the designated footprint. The host State or Territory retains full sovereignty outside that footprint."}, {"id": "s17-2-a", "num": "§17.2.a", "name": "Bid Process and Requirements Specification", "text": "Before issuing a call for bids, the PM publishes a Seat of Government Requirements Specification to the NRS defining the minimum functional, security, physical, and operational requirements any hosting bid must meet; the Legislature establishes by statute the specific standards within those categories. Any State or Territory may submit a bid specifying the proposed property, terms, and conditions of hosting. The House reviews all submitted bids and selects one by ordinary statute, subject to rev"}, {"id": "s17-2-b", "num": "§17.2.b", "name": "Twenty-Year Review Cycle", "text": "Every twenty years from the date the current hosting statute takes effect, the federal government must issue a new call for bids under the §17.2.a process. All States and Territories, including the current host, may submit bids. If no new bids are submitted, the current arrangement continues under the existing agreement until the next review cycle. If bids are submitted, the House reviews all bids and selects one by ordinary statute."}, {"id": "s17-2-c", "num": "§17.2.c", "name": "Transition Window", "text": "When the Seat of Government moves to a new host following a bid review, a two-year transition window begins from the date the new hosting statute takes effect. During the transition window, the current host continues as the default temporary Seat. The transition statute must specify the handover timeline and conditions. The Legislature may by statute extend the transition window where both the incoming and outgoing host agree that additional time is required. If no agreement on the disposition o"}, {"id": "s17-2-d", "num": "§17.2.d", "name": "No-Bid Scenario", "text": "If no State or Territory submits a bid within the call period, the Senate identifies candidate States and Territories that meet the Requirements Specification published under §17.2.a and presents options to the House within 90 days of the close of the bid period. If the Senate fails to present candidates within 90 days, either executive may petition the Supreme Court, which shall on such petition identify candidates within 30 days applying the same constitutional criteria. The House selects a te"}, {"id": "s17-2-e", "num": "§17.2.e", "name": "Federal Control Within Footprint", "text": "Within the specific registered footprint, the federal government has exclusive operational control. The host State or Territory may not tax federal operations, interfere with federal functions, or apply its own law to federal operations within the footprint."},
  {"id": "s17-2-f", "num": "§17.2.f", "name": "Resident Rights", "text": "Persons residing within any area designated as the federal footprint under §17.3 retain full Article I rights enforceable in federal courts. The host State or Territory may not apply residency-based restrictions on federal footprint residents that conflict with Article I."}, {"id": "s17-3-a", "num": "§17.3.a", "name": "Registration", "text": "Every federal operational use right must be registered on the NRS with precise geographic boundaries, authorized purpose, and termination conditions. There are no unregistered federal land claims. Federal property rights are explicit, bounded, and auditable."}, {"id": "s17-3-b", "num": "§17.3.b", "name": "Termination and Reversion", "text": "When a federal function ends, the Operational Use Right terminates automatically. The federal government must publish notice of termination to the NRS within 30 days. The land and all improvements revert to the host State automatically unless the federal government and host State negotiate a retenti"}, {"id": "s17-3-c", "num": "§17.3.c", "name": "Improvements — Negotiated Settlement", "text": "All improvements on federal Operational Use Rights default to reverting to the host State with the land. The federal government and host State may negotiate a different arrangement within the statutory reversion window. No agreement means automatic reversion at no cost. The burden is on the federal "}, {"id": "s17-3-d", "num": "§17.3.d", "name": "Disputes", "text": "Disputes over use right boundaries, termination, or improvement valuation go to the SC on an expedited track. Neither party may occupy or alter disputed land during pending resolution. The expedited track ensures federal operational continuity — resolution must happen fast enough to maintain the rel"}, {"id": "s17-3-e", "num": "§17.3.e", "name": "Independence Transition", "text": "Where a State achieves independence through §15.4 and §15.5, automatic reversion under §17.3.b does not immediately apply to Operational Use Rights within the departing territory. Use rights continue under the terms of the framework agreement and independence treaty negotiated under §15.5.a. This pr"}, {"id": "s17-4", "num": "§17.4", "name": "The National Trust", "text": "The National Trust holds all federal land not conveyed by statute to States, indigenous compact territories, or private parties. Land disposal requires statute — the executive cannot convey or encumber public land unilaterally, preventing privatization by executive discretion. The National Trust Adm"}, {"id": "s17-4-a", "num": "§17.4.a", "name": "Trust Nature", "text": "National Trust lands are designated as permanent heritage, ecological, or public recreation resources. Trust designation requires a 2/3 vote of both chambers with host State consent. Trust lands are not subject to Operational Use Right termination. The stewardship obligation (§17.4.b) applies from t"}, {"id": "s17-4-b", "num": "§17.4.b", "name": "Stewardship Obligation", "text": "The federal government has an active, enforceable obligation to maintain ecological integrity and public accessibility of National Trust lands. EI monitors stewardship compliance annually, cross-referenced with §1.22 (Right to a Healthy Environment). Failure triggers a mandatory remediation plan rep"}, {"id": "s17-4-c", "num": "§17.4.c", "name": "Co-Management", "text": "States and indigenous nations may enter co-management agreements with the Domestic Affairs Council for National Trust lands within their borders or ancestral territories. Co-management does not transfer Trust ownership or alter the constitutional Trust status. Indigenous nations' participation refle"}, {"id": "s17-4-d", "num": "§17.4.d", "name": "Reclassification Threshold", "text": "Land may be removed from National Trust designation only by a 2/3 vote of both chambers with host State consent, followed by SC review within 60 days. The SC reviews whether the removal complies with any applicable international obligations. Removal is permanent — land removed from Trust does not au"}, {"id": "s17-4-e", "num": "§17.4.e", "name": "International Sites", "text": "National Trust lands recognized under international conservation agreements require a 2/3 Senate vote to withdraw from the relevant international obligation before the national removal process begins. The Republic cannot quietly delist internationally recognized sites without formal democratic actio"}, {"id": "s17-4-f", "num": "§17.4.f", "name": "Admission of New Trust Lands", "text": "Land may be designated National Trust by a 2/3 vote of both chambers with host State consent (land in Territories: 2/3 vote alone). No executive action may designate Trust lands — designation is a legislative act. Prevents executive land grabs under Trust designation and executive stripping of Trust"}, {"id": "s17-4-g", "num": "§17.4.g", "name": "National Trust Administrator", "text": "The NTA is a statutory independent officer under §3.7 — the legislature creates the office by statute and calibrates its independence, term, and removal grounds through the enabling statute. The constitutional protections that matter for the Trust are in §17.4.a–f: the trust nature, the 65% referend"}, {"id": "s17-5", "num": "§17.5", "name": "Federal Property in Territories", "text": "Federal use rights in Territories follow the same framework as in States — Operational Use Rights (§17.3) and National Trust (§17.4) — without requiring host State legislative consent (Territories have no State legislature). The Territory's representative body and the LI are consulted. Same constitu"}, {"id": "s18-1-a", "num": "§18.1.a", "name": "Financial Contributions as Electoral Acts", "text": "Electoral Finance Disclosure — all contributions above the de minimis threshold must be publicly disclosed to the Electoral Commission and published to the NRS. Anonymity in electoral finance is prohibited. The de minimis threshold may not be set so high that it effectively permits anonymous large-s"}, {"id": "s18-1-b", "num": "§18.1.b", "name": "Natural Persons Only", "text": "Contribution Limits — individual contributions to electoral campaigns are capped at a level defined by statute. Corporate, organizational, and foreign contributions are prohibited. The prohibition on foreign contributions applies to any person or entity that is not a Republic citizen or resident."}, {"id": "s18-1-c", "num": "§18.1.c", "name": "Voter-Donor Parity", "text": "Independent Expenditure Disclosure — expenditures made independently of but in support of a campaign must also be disclosed. Independent expenditures are not subject to the same contribution limits as direct contributions, but are subject to the same disclosure requirements. Coordinated expenditures"}, {"id": "s18-1-d", "num": "§18.1.d", "name": "Full Disclosure", "text": "EC Administration — the Electoral Commission administers all electoral finance rules, reviews all disclosed contributions, publishes all disclosures to the NRS, and investigates suspected violations. The EI audits EC administration annually. Candidates who receive impermissible contributions must re"}, {"id": "s18-2-a", "num": "§18.2.a", "name": "Qualification Threshold", "text": "Campaign Conduct Standards — candidates for constitutional office must campaign in compliance with published EC conduct standards: prohibition on demonstrably false statements of material fact about a candidate's recorded votes — specifically, claiming a vote was cast when it was not, or was not cast when it was; characterization, emphasis, and contextual framing of voting records are protected expression and are not subject to EC conduct review, prohibition on impersonating other candidates, pr"}, {"id": "s18-2-b", "num": "§18.2.b", "name": "Adequate Allocation", "text": "Media and Communication Standards — campaign communications must clearly identify their sponsor. Fabricated or deceptively edited communications about other candidates are prohibited. Violations are reportable to the EI and may result in contribution return orders."}, {"id": "s18-2-c", "num": "§18.2.c", "name": "Optional Participation", "text": "Foreign Interference — any attempt by a foreign government, foreign national, or foreign-controlled entity to influence a Republic election is a constitutional breach. Both the EI and the President's intelligence domain have concurrent obligations to monitor and report foreign electoral interference"}, {"id": "s18-2-d", "num": "§18.2.d", "name": "EC Administration", "text": "Incumbent Advantage Rules — constitutional officeholders standing for election in a different race must observe strict separation between their official functions and their campaign activities. Official resources — staff, communications, facilities — may not be used for campaign purposes. The EI aud"}, {"id": "s18-3-a", "num": "§18.3.a", "name": "Separation from the Voting System", "text": "Public Campaign Financing Structure — consistent with §10.3.a, the public financing system provides all registered candidates with equal baseline funding. Candidates who opt into the public system accept the contribution cap in exchange for public funding. Candidates who opt out may raise private co"}, {"id": "s18-3-b", "num": "§18.3.b", "name": "Registry Contents", "text": "Matching Funds — the Legislature may by statute create a matching funds component providing additional public funds that match small contributions from citizens. Matching funds incentivize broad citizen participation in campaign financing rather than reliance on a small number of large donors."}, {"id": "s18-3-c", "num": "§18.3.c", "name": "Aggregate Attribution", "text": "EC Allocation of Public Funds — the EC allocates public campaign funds based on objective criteria published before each election cycle. Allocation criteria may not be set in a way that systematically advantages incumbents or established parties."}, {"id": "s18-3-d", "num": "§18.3.d", "name": "Administration", "text": "Financial contributions to electoral campaigns are not constitutionally protected speech under §1.4, and are not protected as associational activity under §1.7. The regulation of electoral finance is a matter of democratic integrity explicitly reserved from both speech and associational protection. "}, {"id": "s19-1", "num": "§19.1", "name": "The Activation Threshold", "text": "Three subsections after v145 restructuring: activation threshold (§19.1.a), institutional accommodation for existing legal structures (§19.1.b), and multi-founder formation for sovereign nations pooling sovereignty (§19.1.c). Previously a single wall-of-text paragraph — restructuring makes §19.1 rea"}, {"id": "s19-1-a", "num": "§19.1.a", "name": "Activation Threshold", "text": "Activated upon: (1) interim EC certification that the NVS is operational and meets §16.3; and (2) a national ratification vote achieving 60% affirmative support with at least 50% participation. The NVS certification requirement ensures the system that conducts the ratification vote meets constitutio"}, {"id": "s19-1-b", "num": "§19.1.b", "name": "Institutional Accommodation", "text": "Where the ratifying polity maintains existing institutions overlapping with constitutional mechanisms, the Legislature must by statute within two years of Phase 4 define their relationship with the constitutional framework. Non-diminishment: accommodation statutes may not reduce legal standing of pr"}, {"id": "s19-1-c", "num": "§19.1.c", "name": "Multi-Founder Formation", "text": "Where multiple sovereign nations simultaneously pool sovereignty through a treaty of union, transition provisions adapt: joint Phase 0/1 certification, consolidated debt assumption, combined Day Zero NRS publication of all founding sovereigns' records, and proportional obligation assumption per trea"}, {"id": "s19-2", "num": "§19.2", "name": "Day Zero", "text": "Day Zero is the date the ratification threshold is certified as achieved by the interim EC. Upon ratification: all laws conflicting with the Individual Sovereignty Floor are immediately null and void; all public assets transfer to the NRS; the 24-month Transition Window begins. The Republic exists t"}, {"id": "s19-3", "num": "§19.3", "name": "The Four-Phase Transition", "text": "24-month, four-phase process. Seven provisions: Phase 0 pre-ratification preparation (§19.3.a), Phase 1 emergency stabilisation Days 1-90 (§19.3.b), Phase 2 institutional construction Days 91-270 (§19.3.c), Phase 3 first elections Days 271-450 (§19.3.d), Phase 4 full operation (§19.3.e), provisional"}, {"id": "s19-3-a", "num": "§19.3.a", "name": "Phase 0 — Pre-Ratification Preparation", "text": "Phase 0 is the pre-ratification preparation period. The interim Electoral Commission is constituted, the National Voting System is certified operational, and the joint Inspectorate panel is formed — all before any ratification vote occurs. The Republic's constitutional infrastructure must exist befo"}, {"id": "s19-3-b", "num": "§19.3.b", "name": "Phase 1 — Emergency Stabilization (Days 1–90)", "text": "Existing government officials serve as caretakers under §19.4. The joint Inspectorate panel assumes oversight. The NRS begins recording all government acts. Priority functions: Basic Needs Floor delivery continuity, public safety, and essential services. No new permanent legislation. This phase is e"}, {"id": "s19-3-c", "num": "§19.3.c", "name": "Phase 2 — Institutional Construction (Days 91–270)", "text": "Phase 2 (Days 91–270) is Institutional Construction. Statehood Audits are conducted for all entering territories. Inspectorates are formally constituted. The Candidate Register for MA board members and the RSA Director is assembled. Electoral Commission is certified as operational. The National Voti"}, {"id": "s19-3-d", "num": "§19.3.d", "name": "Phase 3 — First Elections (Days 271–450)", "text": "Phase 3 (Days 271-450) is First Elections. The first National Election Day. Supreme Court justices elected through the open-candidacy judicial selection process. Electoral Commission inaugural elections. Phase 3 ends when the first the Legislature is sworn in and the first executives take office — t"}, {"id": "s19-3-e", "num": "§19.3.e", "name": "Phase 4 — Full Constitutional Operation", "text": "Phase 4 is Full Constitutional Operation — beginning the day the first Legislature convenes and the first executives take the constitutional oath. From Phase 4, all constitutional provisions are fully operative. The 18-month Transition Window concludes at the end of Phase 4."}, {"id": "s19-4", "num": "§19.4", "name": "Caretaker Status", "text": "All existing government officials serve as caretakers during the Transition Window — restricted to maintaining existing services only. No new permanent legislation. Transition supervised by joint Inspectorate panel: one representative per Inspectorate, appointed by their respective IGs. The panel di"}, {"id": "s19-5", "num": "§19.5", "name": "Pre-Constitutional Classified Documents", "text": "Legislature must establish a Classification Review Commission within 90 days of Phase 4 activation. Commission applies §9.5 criteria to predecessor classified material: legitimately classified material enters the §9.5 duration framework from Day Zero; improperly classified material (concealing viola"}, {"id": "s19-6", "num": "§19.6", "name": "Pre-Existing Obligations", "text": "The Republic assumes the public debt obligations of its predecessor government as a constitutional matter, not a discretionary choice. This prevents the Republic from being born into sovereign default by simply denying predecessor debts — a move that would destabilize the fiscal foundations of the t"}, {"id": "s19-6-a", "num": "§19.6.a", "name": "Debt Assumption", "text": "The Republic assumes all legally recognized debts of the prior government. The Republic does not inherit a clean slate — it inherits what was borrowed. Selective repudiation of prior obligations is not available as a founding act."}, {"id": "s19-6-b", "num": "§19.6.b", "name": "Active Military Operations", "text": "Active military operations of the prior government continue under existing authorization until the §12.2 Tier framework can apply. The President, once inaugurated, must certify each active operation under the appropriate Tier within 14 days or begin orderly cessation. Operations not certified within"}, {"id": "s19-6-c", "num": "§19.6.c", "name": "Social Insurance Programs", "text": "Existing social insurance programs — retirement pensions, disability benefits, health coverage — of the prior government continue uninterrupted during the Transition Window. The Republic does not create a gap in social protection as part of its founding."}, {"id": "s19-6-d", "num": "§19.6.d", "name": "Veterans and National Service Obligations", "text": "The Republic inherits and honors all benefit obligations to persons who served in military or national service roles under the prior government. These are existing contractual commitments of the sovereign that survive transition as continuity-of-state. Legislature must pass a Veterans and National S"}, {"id": "s19-6-e", "num": "§19.6.e", "name": "Constitutional Claims Court", "text": "The immediate nullification of laws conflicting with the Individual Sovereignty Floor creates constitutional disputes that existing courts may not have capacity to absorb. The Legislature must by statute establish an interim Constitutional Claims Court within Phase 2, with jurisdiction over all Arti"}, {"id": "s19-6-f", "num": "§19.6.f", "name": "Legal Continuity", "text": "The Federated Republic is the legal continuation of the prior government as a matter of international law. All international obligations, financial commitments, treaty relationships, and contractual obligations of the prior government as of Day Zero are assumed by the Republic as its successor sover"}, {"id": "s19-7-a", "num": "§19.7.a", "name": "Transition-Period Territorial Elections", "text": "Territories or subdivisions meeting the §13.2 Competency Baseline by Phase 2 end may petition to enter as State or Territory. Those failing the Baseline enter as Territory under §13.1 and may begin the Statehood Audit immediately. Any territory may choose Territory status by simple legislative vote "}, {"id": "s19-7-b", "num": "§19.7.b", "name": "Subdivision Elections", "text": "Prior government states or territories may voluntarily subdivide during the Transition Window by vote of their existing legislative body. New subdivisions are treated as separate petitioning entities for §19.7.a purposes. Legislature must establish by statute the subdivision recognition process."}, {"id": "s19-7-c", "num": "§19.7.c", "name": "Phase 2 Statehood Audit Failures", "text": "Where a state fails the Phase 2 Statehood Audit, it enters as a Territory under §13.1 rather than a State. Its population retains all Article I rights. Territory residents from failed-audit states participate in first House elections proportionally. Audit failure does not disenfranchise the populati"}, {"id": "s19-7-d", "num": "§19.7.d", "name": "Pre-Existing Territories and the District", "text": "All prior government territories that have not achieved statehood by Day Zero enter as Territories from Phase 4 activation — without undergoing Phase 2 Statehood Audits, beginning the standard §13.2 Statehood Audit process after Phase 4. Any capital district or special administrative region that was"}, {"id": "s19-8", "num": "§19.8", "name": "Transition Candidate Registers", "text": "The joint Inspectorate panel assembles the initial Candidate Registers for all constitutionally established positions before Phase 3 elections can occur. Without populated registers, the elections cannot proceed — the Registers are a constitutional prerequisite for the democratic machinery to activa"}, {"id": "s19-8-a", "num": "§19.8.a", "name": "Initial Register Assembly", "text": "During Phase 2, the joint Inspectorate panel assembles an initial Candidate Register for the MA board members and RSA Director. Panel receives disclosure records, reviews factual accuracy, applies constitutional eligibility criteria, and publishes with recommendations to NRS. May draw on prior gover"}, {"id": "s19-8-b", "num": "§19.8.b", "name": "Interim Functions and First Nomination", "text": "The joint Inspectorate panel performs interim MA fiscal certification functions from Phase 4 activation until the first MA Director takes office following the Phase 3 election. These interim certifications carry full constitutional weight. The first PM must nominate MA board members within 90 days o"}, {"id": "s19-9", "num": "§19.9", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity's predecessor government has documented constitutional violations — systematic rights abuses, documented atrocities — the Republic may establish a Transitional Accountability Mechanism by statute. The TAM is time-limited, non-criminal (it cannot impose criminal sentences), a"}, {"id": "s19-9-a", "num": "§19.9.a", "name": "TAM Establishment and Scope", "text": "The Transitional Accountability Mechanism investigates, documents, and recommends remedies for serious violations committed by predecessor government entities during the period before ratification. Its jurisdiction is bounded to predecessor-era conduct — it does not adjudicate Republic-era acts, whi"}, {"id": "s19-9-b", "num": "§19.9.b", "name": "TAM Amendment and Successor Bar", "text": "The establishing statute and any amendments to it require the same 2/3 majority of both chambers as the original statute. No amendment may expand the Mechanism's subject matter scope beyond the scope defined in the establishing statute."}, {"id": "s19-9-c", "num": "§19.9.c", "name": "TAM Jurisdiction and Publication Limits", "text": "The Mechanism may not exercise criminal jurisdiction — that remains with the courts. The Mechanism may not issue orders whose practical effect is equivalent to criminal punishment, including mandatory prosecution referrals with binding recommendations, civil..."}, {"id": "s19-9-d", "num": "§19.9.d", "name": "TAM Sunset and Rationale", "text": "At sunset the Mechanism dissolves; its NRS record is permanent. The Legislature may not extend the Mechanism beyond its statutory sunset without a fresh 2/3 supermajority in both chambers; extension is not a renewal and does not reset the ten-year successor bar..."}, {"id": "s20-1", "num": "§20.1", "name": "Associated Community Status", "text": ""}, {"id": "s20-2", "num": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. "}, {"id": "s20-3", "num": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorise, or systematically permit torture, slavery, or the denial of habeas corpus to any person within its jurisdiction. The Judicial Inspectorate certifies..."}, {"id": "s20-4", "num": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination by the Associated..."}];